import { GoogleGenAI, Type } from "@google/genai";
import { LineItem } from "../types";
import { v4 as uuidv4 } from 'uuid'; // We will simulate uuid since we don't have the lib, see simple helper below

// Simple ID generator if uuid is not available in environment
const generateId = () => Math.random().toString(36).substring(2, 9);

export const parseInvoiceItemsFromText = async (text: string): Promise<LineItem[]> => {
  if (!process.env.API_KEY) {
    console.warn("API Key not found. Returning empty list.");
    return [];
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Parse the following text into a list of invoice line items. Return a JSON array. Text: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              quantity: { type: Type.NUMBER },
              unitPrice: { type: Type.NUMBER }
            },
            required: ["description", "quantity", "unitPrice"]
          }
        }
      }
    });

    const jsonStr = response.text || "[]";
    const parsed = JSON.parse(jsonStr);

    // Map to internal LineItem format
    return parsed.map((item: any) => ({
      id: generateId(),
      description: item.description,
      quantity: Number(item.quantity) || 1,
      unitPrice: Number(item.unitPrice) || 0
    }));

  } catch (error) {
    console.error("Error parsing invoice items with Gemini:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Client, MOCK_CLIENTS } from '../types';
import { Search, X, User } from 'lucide-react';

interface ClientSelectorProps {
  selectedClient: Client | null;
  onSelectClient: (client: Client | null) => void;
}

const ClientSelector: React.FC<ClientSelectorProps> = ({ selectedClient, onSelectClient }) => {
  const [query, setQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredClients = MOCK_CLIENTS.filter(client =>
    client.name.toLowerCase().includes(query.toLowerCase())
  );

  const handleSelect = (client: Client) => {
    onSelectClient(client);
    setQuery('');
    setIsOpen(false);
  };

  const handleClear = () => {
    onSelectClient(null);
    setQuery('');
  };

  if (selectedClient) {
    return (
      <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm relative group">
        <div className="absolute top-2 right-2">
           <button 
             onClick={handleClear}
             className="text-slate-400 hover:text-red-500 transition-colors p-1"
           >
             <X size={16} />
           </button>
        </div>
        <div className="flex items-start space-x-3">
          <div className="bg-blue-100 p-2 rounded-full text-blue-600">
             <User size={20} />
          </div>
          <div>
            <h3 className="font-semibold text-slate-800">{selectedClient.name}</h3>
            <p className="text-sm text-slate-500 whitespace-pre-line">{selectedClient.address}</p>
            <p className="text-sm text-slate-400 mt-1">{selectedClient.email}</p>
            {selectedClient.vatId && <p className="text-xs text-slate-400 mt-1">VAT: {selectedClient.vatId}</p>}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="relative">
      <div className="relative">
        <input
          type="text"
          className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
          placeholder="Search for a client..."
          value={query}
          onChange={(e) => {
            setQuery(e.target.value);
            setIsOpen(true);
          }}
          onFocus={() => setIsOpen(true)}
        />
        <Search className="absolute left-3 top-3.5 text-slate-400" size={18} />
      </div>

      {isOpen && query.length > 0 && (
        <div className="absolute z-20 w-full mt-2 bg-white rounded-lg shadow-xl border border-slate-100 max-h-60 overflow-y-auto">
          {filteredClients.length > 0 ? (
            filteredClients.map(client => (
              <button
                key={client.id}
                onClick={() => handleSelect(client)}
                className="w-full text-left px-4 py-3 hover:bg-slate-50 border-b border-slate-50 last:border-0 transition-colors flex items-center space-x-3"
              >
                 <div className="bg-slate-100 p-2 rounded-full text-slate-500">
                   <User size={16} />
                 </div>
                 <div>
                   <div className="font-medium text-slate-700">{client.name}</div>
                   <div className="text-xs text-slate-500 truncate">{client.email}</div>
                 </div>
              </button>
            ))
          ) : (
             <div className="px-4 py-3 text-slate-400 text-sm text-center">No clients found.</div>
          )}
        </div>
      )}
    </div>
  );
};

export default ClientSelector;

import React, { useState } from 'react';
import { parseInvoiceItemsFromText } from '../services/geminiService';
import { LineItem } from '../types';
import { Sparkles, Loader2, ArrowRight } from 'lucide-react';

interface SmartInputProps {
  onItemsParsed: (items: LineItem[]) => void;
}

const SmartInput: React.FC<SmartInputProps> = ({ onItemsParsed }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleParse = async () => {
    if (!input.trim()) return;
    setLoading(true);
    setError(null);
    try {
      const items = await parseInvoiceItemsFromText(input);
      onItemsParsed(items);
      setInput('');
    } catch (err) {
      setError("Failed to parse. Please check your API key or try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-gradient-to-br from-indigo-50 to-blue-50 border border-blue-100 rounded-xl p-5 mb-6">
      <div className="flex items-center space-x-2 mb-3 text-indigo-700">
        <Sparkles size={18} />
        <h3 className="font-semibold text-sm uppercase tracking-wide">AI Magic Fill</h3>
      </div>
      <p className="text-slate-600 text-sm mb-3">
        Paste a work log or describe items naturally (e.g., "Web design 10 hours at $50, Hosting $20").
      </p>

      <div className="relative">
        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type here..."
          className="w-full p-3 pr-12 rounded-lg border border-blue-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-sm shadow-sm min-h-[80px]"
        />
        <button
          onClick={handleParse}
          disabled={loading || !input.trim()}
          className="absolute bottom-3 right-3 bg-indigo-600 text-white p-2 rounded-full hover:bg-indigo-700 disabled:bg-indigo-300 disabled:cursor-not-allowed transition-all shadow-md"
        >
          {loading ? <Loader2 size={16} className="animate-spin" /> : <ArrowRight size={16} />}
        </button>
      </div>
      {error && <p className="text-red-500 text-xs mt-2">{error}</p>}
    </div>
  );
};

export default SmartInput;

import React, { useState } from 'react';
