             <div className="mt-4">
                <label className="block text-xs font-medium text-slate-500 mb-1">Notes</label>
                 <textarea 
                    value={invoiceData.notes}
                    onChange={(e) => setInvoiceData(prev => ({...prev, notes: e.target.value}))}
