import React, { useState, useRef } from 'react';
import { SenderDetails, Client } from '../types';
import { X, Upload, Save, Trash2, User, CreditCard, Building, Settings as SettingsIcon } from 'lucide-react';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  senderDetails: SenderDetails;
  onUpdateSender: (details: SenderDetails) => void;
  logo: string | undefined;
  onUpdateLogo: (base64: string) => void;
  invoicePrefix: string;
  onUpdatePrefix: (prefix: string) => void;
  clients: Client[];
  onDeleteClient: (id: string) => void;
}

type Tab = 'company' | 'payment' | 'preferences' | 'clients';

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  senderDetails,
  onUpdateSender,
  logo,
  onUpdateLogo,
  invoicePrefix,
  onUpdatePrefix,
  clients,
  onDeleteClient
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('company');
  const [localSender, setLocalSender] = useState<SenderDetails>(senderDetails);
  const [localPrefix, setLocalPrefix] = useState(invoicePrefix);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleSave = () => {
    onUpdateSender(localSender);
    onUpdatePrefix(localPrefix);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateLogo(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateSenderField = (field: keyof SenderDetails, value: string) => {
    setLocalSender(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 print:hidden">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <SettingsIcon size={20} className="text-blue-600" />
            <span>Settings</span>
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('company')}
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'company' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <Building size={16} /> Company
          </button>
          <button 
            onClick={() => setActiveTab('payment')}
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'payment' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <CreditCard size={16} /> Payment
          </button>
          <button 
            onClick={() => setActiveTab('preferences')}
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'preferences' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <SettingsIcon size={16} /> Prefs
          </button>
          <button 
            onClick={() => setActiveTab('clients')}
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'clients' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <User size={16} /> Clients
          </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1">
