import React, { useState, useRef } from 'react';
import { SenderDetails, Client } from '../types';
import { X, Upload, Save, Trash2, User, CreditCard, Building, Settings as SettingsIcon, LayoutTemplate, Droplets } from 'lucide-react';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  senderDetails: SenderDetails;
  onUpdateSender: (details: SenderDetails) => void;
  logo: string | undefined;
  onUpdateLogo: (base64: string) => void;
  invoicePrefix: string;
  onUpdatePrefix: (prefix: string) => void;
  clients: Client[];
  onDeleteClient: (id: string) => void;
  templateId: string;
  onUpdateTemplate: (id: string) => void;
  showWatermark: boolean;
  onToggleWatermark: (show: boolean) => void;
}

type Tab = 'company' | 'payment' | 'preferences' | 'clients' | 'templates';

const TEMPLATE_OPTIONS = [
  { id: 'classic-blue', name: 'Classic Blue', color: 'bg-[#0e3a5d]' },
  { id: 'classic-red', name: 'Classic Red', color: 'bg-[#7f1d1d]' },
  { id: 'classic-green', name: 'Classic Green', color: 'bg-[#064e3b]' },
  { id: 'modern-sidebar', name: 'Modern Sidebar', color: 'bg-slate-700' },
  { id: 'midnight-sidebar', name: 'Midnight Sidebar', color: 'bg-black' },
  { id: 'teal-sidebar', name: 'Teal Sidebar', color: 'bg-teal-600' },
  { id: 'minimalist', name: 'Minimalist', color: 'bg-slate-200 border-slate-400' },
  { id: 'minimalist-blue', name: 'Minimalist Blue', color: 'bg-blue-100 border-blue-400' },
  { id: 'bold-header', name: 'Bold Orange', color: 'bg-orange-500' },
  { id: 'corporate-grey', name: 'Corporate Grey', color: 'bg-slate-500' },
];

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  senderDetails,
  onUpdateSender,
  logo,
  onUpdateLogo,
  invoicePrefix,
  onUpdatePrefix,
  clients,
  onDeleteClient,
  templateId,
  onUpdateTemplate,
  showWatermark,
  onToggleWatermark
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('company');
  const [localSender, setLocalSender] = useState<SenderDetails>(senderDetails);
  const [localPrefix, setLocalPrefix] = useState(invoicePrefix);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleSave = () => {
    onUpdateSender(localSender);
    onUpdatePrefix(localPrefix);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateLogo(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateSenderField = (field: keyof SenderDetails, value: string) => {
    setLocalSender(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 print:hidden">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
