import React, { useState, useEffect } from 'react';
import LandingPage from './components/LandingPage';
import PaymentPage from './components/PaymentPage';
import InvoiceDashboard from './components/InvoiceDashboard';

type ViewState = 'landing' | 'payment' | 'dashboard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('landing');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if user has already paid/accessed the app
    const hasAccess = localStorage.getItem('invoicify_access');
    if (hasAccess === 'true') {
      setView('dashboard');
    }
    setLoading(false);
  }, []);

  const handlePaymentSuccess = () => {
    localStorage.setItem('invoicify_access', 'true');
    setView('dashboard');
  };

  const handleLogout = () => {
    // Optional: Clear access to reset flow for demo purposes
    // localStorage.removeItem('invoicify_access'); 
    setView('landing');
  };

  if (loading) return null;

  switch (view) {
    case 'landing':
      return <LandingPage onGetStarted={() => setView('payment')} />;
    case 'payment':
      return <PaymentPage onPaymentSuccess={handlePaymentSuccess} />;
    case 'dashboard':
      return <InvoiceDashboard onLogout={handleLogout} />;
    default:
      return <LandingPage onGetStarted={() => setView('payment')} />;
  }
};

export default App;

import React, { useState } from 'react';
import { CreditCard, Lock, Check, Loader2, ShieldCheck } from 'lucide-react';

interface PaymentPageProps {
  onPaymentSuccess: () => void;
}

const PaymentPage: React.FC<PaymentPageProps> = ({ onPaymentSuccess }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  const handlePay = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // Simulate API call
    setTimeout(() => {
      setIsProcessing(false);
      onPaymentSuccess();
    }, 2000);
  };

  // Simple formatter for visual appeal
  const formatCard = (val: string) => {
    return val.replace(/\D/g, '').replace(/(\d{4})(?=\d)/g, '$1 ').trim().substring(0, 19);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4 font-sans">
      <div className="max-w-4xl w-full grid md:grid-cols-2 bg-white rounded-2xl shadow-2xl overflow-hidden">

