                      >
                         <FileText size={14} />
                         <span>Invoice</span>
                      </button>
                      <button 
                        onClick={() => setInvoiceData(prev => ({...prev, type: 'quotation'}))}
                        className={`flex-1 flex items-center justify-center space-x-2 py-2 text-sm rounded-md transition-all ${invoiceData.type === 'quotation' ? 'bg-white shadow text-slate-900 font-medium' : 'text-slate-500'}`}
                      >
                         <FileText size={14} />
                         <span>Quotation</span>
                      </button>
                   </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">
                        {invoiceData.type === 'invoice' ? 'Invoice #' : 'Quotation #'}
                     </label>
                     <input 
                        type="text" 
                        value={invoiceData.invoiceNumber}
                        onChange={(e) => setInvoiceData(prev => ({...prev, invoiceNumber: e.target.value}))}
                        className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                     />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Date</label>
                     <input 
                        type="date" 
                        value={invoiceData.date}
                        onChange={(e) => setInvoiceData(prev => ({...prev, date: e.target.value}))}
                        className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                     />
                   </div>
                 </div>
               </div>
            </section>
          </div>
        </div>

        {/* Preview Panel (Right) */}
        <div className={`w-full md:w-7/12 lg:w-8/12 bg-slate-100 h-[calc(100vh-60px)] md:h-screen overflow-y-auto relative ${activeTab === 'edit' ? 'hidden md:block' : ''}`}>

          {/* Header Actions */}
          <div className="sticky top-0 z-10 p-4 flex justify-between items-center pointer-events-none">
             {/* Back Button (Mobile Only) */}
             <div className="pointer-events-auto">
                <button 
                  onClick={() => setActiveTab('edit')}
                  className="md:hidden bg-white/90 backdrop-blur text-slate-700 px-4 py-2.5 rounded-full shadow-lg border border-slate-200 flex items-center space-x-2 font-medium active:scale-95"
                >
                  <ArrowLeft size={18} />
                  <span>Back</span>
                </button>
             </div>

             {/* Action Buttons */}
             <div className="pointer-events-auto flex space-x-3">
                <button 
                  onClick={handleManualSave}
                  className="bg-white text-slate-600 px-4 py-2.5 rounded-full shadow-lg border border-slate-200 hover:bg-slate-50 transition-all flex items-center space-x-2 font-medium active:scale-95"
                  title="Save Draft"
                >
                  <SaveIcon size={18} />
                </button>
                <button 
                  onClick={handleEmail}
                  className="bg-white text-slate-700 px-5 py-2.5 rounded-full shadow-lg border border-slate-200 hover:bg-slate-50 transition-all flex items-center space-x-2 font-medium active:scale-95"
                >
                  <Mail size={18} />
                  <span>Email</span>
                </button>
                <button 
                  onClick={handleExport}
                  disabled={isExporting}
                  className="bg-slate-900 text-white px-5 py-2.5 rounded-full shadow-lg hover:bg-slate-800 hover:shadow-xl transition-all flex items-center space-x-2 font-medium active:scale-95 disabled:bg-slate-600 disabled:cursor-not-allowed"
                >
                  {isExporting ? <Loader2 size={18} className="animate-spin" /> : <Download size={18} />}
                  <span>{isExporting ? 'Generating...' : 'PDF'}</span>
                </button>
             </div>
          </div>

          <div className="p-2 md:p-8 lg:p-12 flex justify-center items-start min-h-full overflow-hidden pb-20">
             {/* Responsive Scaling for Visual Preview */}
             <div className="transform scale-[0.42] sm:scale-[0.6] md:scale-[0.85] lg:scale-100 origin-top shadow-2xl transition-transform duration-300 bg-white">
                <InvoicePreview 
                  data={invoiceData} 
                  logoSrc={customLogo} 
                  templateId={templateId}
                  showWatermark={showWatermark}
                  customThemes={customThemes}
                  customWatermark={customWatermark}
                  watermarkOpacity={watermarkOpacity}
                />
             </div>
          </div>
        </div>
      </div>

      {/* 
        OFF-SCREEN EXPORT CONTAINER
        Positioned off-screen to remain in DOM for html2canvas but invisible to user.
      */}
      <div style={{ position: 'fixed', left: '-9999px', top: 0 }}>
        <div ref={exportRef} className="w-[210mm] min-h-[297mm] bg-white">
            <InvoicePreview 
                data={invoiceData} 
                logoSrc={customLogo} 
                templateId={templateId}
                showWatermark={showWatermark}
                customThemes={customThemes}
                customWatermark={customWatermark}
                watermarkOpacity={watermarkOpacity}
            />
        </div>
      </div>
    </>
  );
};

export default InvoiceDashboard;

import React, { useState, useRef } from 'react';
import { SenderDetails, Client, InvoiceTheme, DEFAULT_THEMES } from '../types';
import { X, Upload, Save, Trash2, User, CreditCard, Building, Settings as SettingsIcon, LayoutTemplate, Droplets, Plus, Palette, FileJson, Image as ImageIcon, Download, Sliders, Copy } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  senderDetails: SenderDetails;
  onUpdateSender: (details: SenderDetails) => void;
  logo: string | undefined;
  onUpdateLogo: (base64: string) => void;
  invoicePrefix: string;
  onUpdatePrefix: (prefix: string) => void;
  clients: Client[];
  onDeleteClient: (id: string) => void;
  templateId: string;
  onUpdateTemplate: (id: string) => void;
  showWatermark: boolean;
  onToggleWatermark: (show: boolean) => void;
  customThemes?: InvoiceTheme[];
  onAddTheme?: (theme: InvoiceTheme) => void;
  onDeleteTheme?: (id: string) => void;
  onUpdateCustomThemeDetails?: (theme: InvoiceTheme) => void; // New prop for updating existing themes
  customWatermark?: string;
  onUpdateCustomWatermark?: (base64: string) => void;
  watermarkOpacity?: number;
  onUpdateWatermarkOpacity?: (opacity: number) => void;
}

type Tab = 'company' | 'payment' | 'preferences' | 'clients' | 'templates';

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  senderDetails,
  onUpdateSender,
  logo,
  onUpdateLogo,
  invoicePrefix,
  onUpdatePrefix,
  clients,
  onDeleteClient,
  templateId,
  onUpdateTemplate,
  showWatermark,
  onToggleWatermark,
  customThemes = [],
  onAddTheme,
  onDeleteTheme,
  onUpdateCustomThemeDetails,
  customWatermark,
  onUpdateCustomWatermark,
  watermarkOpacity = 10,
  onUpdateWatermarkOpacity
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('company');
  const [localSender, setLocalSender] = useState<SenderDetails>(senderDetails);
  const [localPrefix, setLocalPrefix] = useState(invoicePrefix);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const watermarkInputRef = useRef<HTMLInputElement>(null);
  const themeFileInputRef = useRef<HTMLInputElement>(null);
  const bgImageInputRef = useRef<HTMLInputElement>(null);

  // Template Creator State
  const [isCreatingTheme, setIsCreatingTheme] = useState(false);
  const [newTheme, setNewTheme] = useState<Partial<InvoiceTheme>>({
    name: 'My Custom Theme',
    layout: 'standard',
    font: 'sans',
    colors: { primary: '#3b82f6', accent: '#fbbf24', text: '#1f2937', bg: 'white' }
  });

  // Find the currently active custom theme if it exists
  const activeCustomTheme = customThemes.find(t => t.id === templateId);

  if (!isOpen) return null;

  const handleSave = () => {
    onUpdateSender(localSender);
    onUpdatePrefix(localPrefix);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, callback: (base64: string) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        callback(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateSenderField = (field: keyof SenderDetails, value: string) => {
    setLocalSender(prev => ({ ...prev, [field]: value }));
  };

  const handleSaveTheme = () => {
    if (!onAddTheme || !newTheme.name) return;

    const themeToSave: InvoiceTheme = {
        id: `custom-${uuidv4()}`,
        name: newTheme.name,
        layout: newTheme.layout as any || 'standard',
        font: newTheme.font as any || 'sans',
        colors: {
            primary: newTheme.colors?.primary || '#000000',
            accent: newTheme.colors?.accent || '#888888',
            text: '#1f2937',
            bg: 'white',
            headerText: newTheme.layout === 'standard' ? 'white' : undefined,
            sidebarBg: newTheme.layout === 'sidebar' ? newTheme.colors?.primary : undefined,
            sidebarText: 'white'
        },
        isCustom: true,
        backgroundImage: newTheme.backgroundImage
    };

    onAddTheme(themeToSave);
    setIsCreatingTheme(false);
    onUpdateTemplate(themeToSave.id);
  };

  const handleCloneTheme = () => {
    if (!onAddTheme) return;
    // Find standard theme to clone
    const standardTheme = DEFAULT_THEMES[templateId];
    if (!standardTheme) return;

    const clonedTheme: InvoiceTheme = {
      ...JSON.parse(JSON.stringify(standardTheme)),
      id: `custom-${uuidv4()}`,
      name: `${standardTheme.name} (Custom)`,
      isCustom: true,
      customConfig: {
        ...standardTheme.customConfig,
        // Initialize defaults if they don't exist
        logoScale: 100,
        logoX: 0,
        logoY: 0,
        watermarkScale: 100,
        watermarkX: 0,
        watermarkY: 0
      }
    };
    onAddTheme(clonedTheme);
    onUpdateTemplate(clonedTheme.id);
  };

  const handleImportTheme = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && onAddTheme) {
        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const imported = JSON.parse(event.target?.result as string);
                if (imported.name && imported.colors) {
                    const themeWithNewId = { ...imported, id: `imported-${uuidv4()}`, isCustom: true };
                    onAddTheme(themeWithNewId);
                    onUpdateTemplate(themeWithNewId.id);
                } else {
                    alert("Invalid theme file format.");
                }
            } catch (err) {
                alert("Failed to parse JSON file.");
            }
        };
        reader.readAsText(file);
    }
  };

  const handleCreateFromImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    handleFileChange(e, (base64) => {
        if (!onAddTheme) return;
        const themeToSave: InvoiceTheme = {
            id: `img-theme-${uuidv4()}`,
            name: 'Custom Image Theme',
            layout: 'standard', // Image backgrounds usually imply a standard overlay
            font: 'sans',
            colors: {
                primary: '#000000',
                accent: '#000000',
                text: '#000000',
                bg: 'transparent'
            },
            isCustom: true,
            backgroundImage: base64,
            customConfig: {
                backgroundOpacity: 100,
                marginTop: 0,
                marginBottom: 0,
                backgroundScale: 100,
                backgroundPositionX: 50,
                backgroundPositionY: 50,
                logoScale: 100,
                logoX: 0,
                logoY: 0,
                watermarkScale: 100,
                watermarkX: 0,
                watermarkY: 0
            }
        };
        onAddTheme(themeToSave);
        onUpdateTemplate(themeToSave.id);
    });
  };

  const updateActiveThemeConfig = (key: keyof NonNullable<InvoiceTheme['customConfig']>, value: number) => {
    if (activeCustomTheme && onUpdateCustomThemeDetails) {
        const updatedTheme = {
            ...activeCustomTheme,
            customConfig: {
