                                                ref={watermarkInputRef} 
                                                className="hidden" 
                                                accept="image/*"
                                                onChange={(e) => handleFileChange(e, (base64) => onUpdateCustomWatermark && onUpdateCustomWatermark(base64))}
                                            />
                                            <button 
                                                onClick={() => watermarkInputRef.current?.click()}
                                                className="text-xs text-blue-600 hover:underline block mb-1"
                                            >
                                                Upload Image
                                            </button>
                                            {customWatermark && (
                                                <button 
                                                    onClick={() => onUpdateCustomWatermark && onUpdateCustomWatermark('')}
                                                    className="text-xs text-red-500 hover:underline"
                                                >
                                                    Remove Custom Watermark
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                    <p className="text-[10px] text-slate-400 mt-2">Overrides your logo for the watermark.</p>
                                </div>
                            </div>
                          )}
                      </div>
                   </div>
                 </>
               )}
            </div>
          )}

          {activeTab === 'payment' && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               <div>
                 <label className="block text-xs font-medium text-slate-500 mb-1">Account Name</label>
                 <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.accountName} onChange={e => updateSenderField('accountName', e.target.value)} />
               </div>
               <div>
                 <label className="block text-xs font-medium text-slate-500 mb-1">Account Number</label>
                 <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.accountNumber} onChange={e => updateSenderField('accountNumber', e.target.value)} />
               </div>
               <div>
                 <label className="block text-xs font-medium text-slate-500 mb-1">Bank Branch</label>
                 <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.branch} onChange={e => updateSenderField('branch', e.target.value)} />
               </div>
               <div>
                 <label className="block text-xs font-medium text-slate-500 mb-1">IFSC Code</label>
                 <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.ifsCode} onChange={e => updateSenderField('ifsCode', e.target.value)} />
               </div>
               <div>
                 <label className="block text-xs font-medium text-slate-500 mb-1">PAN Number</label>
                 <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.pan} onChange={e => updateSenderField('pan', e.target.value)} />
               </div>
            </div>
          )}

          {activeTab === 'preferences' && (
             <div>
                <label className="block text-xs font-medium text-slate-500 mb-1">Invoice Number Format (Prefix)</label>
                <div className="flex items-center">
                  <input 
                    type="text" 
                    className="w-1/2 border p-2 rounded-l text-sm bg-white" 
                    value={localPrefix} 
                    onChange={e => setLocalPrefix(e.target.value)} 
                    placeholder="e.g. INV-"
                  />
                  <div className="bg-slate-100 border border-l-0 p-2 rounded-r text-sm text-slate-500">00123</div>
                </div>
                <p className="text-xs text-slate-400 mt-2">Example: If you set prefix to "AS", invoice numbers will look like "AS00123".</p>
             </div>
          )}

          {activeTab === 'clients' && (
            <div>
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-semibold text-slate-700">Stored Clients</h3>
                <span className="text-xs text-slate-500">{clients.length} clients found</span>
              </div>
              <div className="bg-slate-50 rounded-lg border border-slate-200 overflow-hidden max-h-[300px] overflow-y-auto">
                <table className="w-full text-sm text-left">
                  <thead className="bg-slate-100 text-slate-500 font-medium">
                    <tr>
                      <th className="p-3">Name</th>
                      <th className="p-3">Email</th>
                      <th className="p-3 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {clients.map(client => (
                      <tr key={client.id} className="border-t border-slate-200 hover:bg-white transition-colors">
                        <td className="p-3 font-medium text-slate-800">{client.name}</td>
                        <td className="p-3 text-slate-600">{client.email || '-'}</td>
                        <td className="p-3 text-right">
                          <button 
                            onClick={() => {
                              if(window.confirm(`Delete client ${client.name}?`)) onDeleteClient(client.id);
                            }}
                            className="text-red-400 hover:text-red-600 p-1"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {clients.length === 0 && (
                      <tr>
                        <td colSpan={3} className="p-6 text-center text-slate-400">No clients stored yet.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-end space-x-3">
          <button 
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            Cancel
          </button>
          <button 
            onClick={handleSave}
            className="px-6 py-2 text-sm font-medium text-white bg-slate-900 hover:bg-slate-800 rounded-lg transition-colors flex items-center space-x-2"
          >
            <Save size={16} />
            <span>Save Settings</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState } from 'react';
import { InvoiceData, InvoiceTheme, DEFAULT_THEMES } from '../types';

interface InvoicePreviewProps {
  data: InvoiceData;
  logoSrc?: string;
  templateId?: string;
  showWatermark?: boolean;
  customThemes?: InvoiceTheme[];
  customWatermark?: string;
  watermarkOpacity?: number;
}

const InvoicePreview: React.FC<InvoicePreviewProps> = ({ 
  data, 
  logoSrc, 
  templateId = 'classic-blue',
  showWatermark = false,
  customThemes = [],
  customWatermark,
  watermarkOpacity = 10
}) => {
  const [timestamp] = useState(Date.now());

  // Merge default themes with custom ones to find the active theme
  const allThemes = { ...DEFAULT_THEMES };
  customThemes.forEach(t => {
    allThemes[t.id] = t;
  });

  const theme = allThemes[templateId] || DEFAULT_THEMES['classic-blue'];

  // Custom Config Extraction
  const bgOpacity = theme.customConfig?.backgroundOpacity !== undefined ? theme.customConfig.backgroundOpacity / 100 : 1;
  const marginTop = theme.customConfig?.marginTop !== undefined ? `${theme.customConfig.marginTop}mm` : undefined;
  const marginBottom = theme.customConfig?.marginBottom !== undefined ? `${theme.customConfig.marginBottom}mm` : undefined;

  // Background Positioning
  const bgScale = theme.customConfig?.backgroundScale !== undefined ? theme.customConfig.backgroundScale / 100 : 1;
  const bgX = theme.customConfig?.backgroundPositionX !== undefined ? theme.customConfig.backgroundPositionX : 50;
  const bgY = theme.customConfig?.backgroundPositionY !== undefined ? theme.customConfig.backgroundPositionY : 50;

  // Logo & Watermark Positioning
  const logoScale = theme.customConfig?.logoScale !== undefined ? theme.customConfig.logoScale / 100 : 1;
  const logoX = theme.customConfig?.logoX ?? 0;
  const logoY = theme.customConfig?.logoY ?? 0;

  const wmScale = theme.customConfig?.watermarkScale !== undefined ? theme.customConfig.watermarkScale / 100 : 1;
  const wmX = theme.customConfig?.watermarkX ?? 0;
  const wmY = theme.customConfig?.watermarkY ?? 0;

  // Helpers
  const currencyFormatter = new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  });

  const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const total = subtotal;
  const isQuotation = data.type === 'quotation';
  const { sender, client, items } = data;

  const formatDate = (d: string) => {
    if (!d) return '';
    const dateObj = new Date(d);
    return dateObj.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
  };

  // --- Subcomponents for Rendering ---

  const Logo = ({ className }: { className?: string }) => (
    <div 
      className={className} 
      style={{ 
        transform: `translate(${logoX}mm, ${logoY}mm) scale(${logoScale})`,
        transformOrigin: 'center center' // or top right depending on layout, but center is safer for general scaling
      }}
    >
      <img 
        src={logoSrc || `/logo.png?t=${timestamp}`}
        alt="Logo" 
        className="h-16 w-auto object-contain"
        onError={(e) => {
           e.currentTarget.style.display = 'none';
           document.getElementById(`fallback-${templateId}`)?.classList.remove('hidden');
        }}
      />
      <div id={`fallback-${templateId}`} className="hidden font-bold text-2xl tracking-tighter border-2 border-current px-2 py-1 inline-block">
        {sender.name.substring(0,2).toUpperCase()}
      </div>
    </div>
  );

  const Watermark = () => {
    if (!showWatermark) return null;
    const watermarkSrc = customWatermark || logoSrc;

    return (
       <div 
         className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 overflow-hidden" 
         style={{ opacity: watermarkOpacity / 100 }}
       >
         <div style={{ transform: `translate(${wmX}mm, ${wmY}mm) scale(${wmScale})` }}>
           {watermarkSrc ? (
              <img src={watermarkSrc} className="w-3/4 max-w-[500px] object-contain" alt="Watermark" />
           ) : (
              <svg width="400" height="400" viewBox="0 0 100 100" fill={theme.colors.primary}>
                 <path d="M50 15 L85 75 H15 L50 15Z" stroke={theme.colors.primary} strokeWidth="5" fill="none" />
                 <text x="50" y="50" textAnchor="middle" fontSize="10" fill={theme.colors.primary}>INVOICE</text>
              </svg>
           )}
         </div>
       </div>
    );
  };

  // --- STANDARD LAYOUT IMPLEMENTATION (New Reference Design) ---

  const TopWave = () => (
    <div className="absolute top-0 left-0 right-0 h-32 z-0 overflow-hidden">
        <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="w-full h-full">
            <path d="M0 0 H100 V30 Q50 60 0 20 Z" fill={theme.colors.primary} />
            <path d="M0 20 Q50 60 100 30 V35 Q50 65 0 25 Z" fill={theme.colors.accent} />
        </svg>
    </div>
  );

  const BottomWave = () => (
    <div className="absolute bottom-0 left-0 right-0 h-32 z-0 overflow-hidden flex items-end">
         <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="w-full h-full">
             <path d="M0 100 H100 V50 Q50 90 0 70 Z" fill={theme.colors.accent} opacity="0.3" /> 
             <path d="M0 100 H100 V80 Q50 100 0 90 Z" fill={theme.colors.primary} />
         </svg>
    </div>
  );

  const ReferenceTable = () => (
    <div className="relative z-10 w-full mb-8">
      <table className="w-full border-collapse">
        <thead>
          <tr style={{ backgroundColor: theme.colors.primary, color: 'white' }}>
            <th className="py-3 px-4 text-left w-[10%] font-serif font-bold uppercase tracking-wider text-sm border-r border-white/10">Item</th>
            <th className="py-3 px-4 text-left w-[50%] font-serif font-bold uppercase tracking-wider text-sm border-r border-white/10">Description</th>
            {isQuotation && (
              <th className="py-3 px-4 text-right w-[20%] font-serif font-bold uppercase tracking-wider text-sm border-r border-white/10">Rate</th>
            )}
            <th className="py-3 px-4 text-right w-[20%] font-serif font-bold uppercase tracking-wider text-sm">Amount</th>
          </tr>
        </thead>
        <tbody>
          {items.map((item, index) => (
            <tr key={item.id} className="border-b border-slate-200">
              <td className="py-6 px-4 align-top text-slate-700 font-medium">{index + 1}.</td>
              <td className="py-6 px-4 align-top text-slate-800 font-medium whitespace-pre-wrap">{item.description}</td>
              {isQuotation && (
                <td className="py-6 px-4 align-top text-right text-slate-600">
                   {currencyFormatter.format(item.unitPrice)}
                </td>
              )}
              <td className="py-6 px-4 align-top text-right font-bold text-slate-900">
                {currencyFormatter.format(item.quantity * item.unitPrice)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  // --- MAIN RENDER ---

  const containerClass = `bg-white shadow-2xl w-[210mm] min-h-[297mm] mx-auto relative flex flex-col overflow-hidden print-exact-a4 ${theme.font === 'serif' ? 'font-serif' : theme.font === 'mono' ? 'font-mono' : 'font-sans'}`;

  // Use the reference design for standard layout
  if (theme.layout === 'standard') {
      return (
        <div className={containerClass}>
            {/* Background Image or Waves */}
            {theme.backgroundImage ? (
                <div className="absolute inset-0 z-0 overflow-hidden" style={{ opacity: bgOpacity }}>
                    <img 
                        src={theme.backgroundImage} 
                        className="w-full h-full object-cover" 
                        style={{ 
                            objectPosition: `${bgX}% ${bgY}%`,
                            transform: `scale(${bgScale})`,
                            transformOrigin: `${bgX}% ${bgY}%`
                        }}
                        alt="" 
                    />
                </div>
            ) : (
                <>
                  <TopWave />
                  <BottomWave />
                </>
            )}

            <div 
                className="relative z-10 px-12 pt-12 flex-grow flex flex-col"
                style={{ paddingTop: marginTop, paddingBottom: marginBottom }}
            >
                {/* Header */}
                <div className="flex justify-between items-start mb-16">
                    <div>
                        <h1 className="text-5xl font-serif text-slate-900 mb-4 tracking-tight">
                            {isQuotation ? 'QUOTATION' : 'INVOICE'}
                        </h1>
                        <div className="text-sm text-slate-600 space-y-1">
                            <p><span className="font-medium">
                                {isQuotation ? 'Date:' : 'Invoice Number:'}
                            </span> {isQuotation ? formatDate(data.date) : data.invoiceNumber}</p>
                            {!isQuotation && <p><span className="font-medium">Date:</span> {formatDate(data.date)}</p>}
                        </div>
                    </div>
                    <div className="text-right">
                        <Logo className="mb-2 flex justify-end origin-right" />
                    </div>
                </div>

                {/* Addresses */}
                <div className="flex gap-12 mb-12">
                    <div className="w-1/2">
                        <h3 className="font-serif font-bold text-sm uppercase mb-3 tracking-widest text-slate-900">
                            {isQuotation ? 'QUOTATION TO:' : 'BILL TO:'}
                        </h3>
                        {client ? (
                            <div className="text-sm text-slate-700 leading-relaxed">
                                <p className="font-bold text-slate-900 text-lg mb-1">{client.name}</p>
                                <p className="whitespace-pre-line mb-2">{client.address}</p>
                                {client.gstin && <p>GSTIN: {client.gstin}</p>}
                                {client.vatId && <p>VAT: {client.vatId}</p>}
                            </div>
                        ) : (
                            <p className="text-slate-400 italic">Select a client...</p>
                        )}
                    </div>
                    <div className="w-1/2">
                        <h3 className="font-serif font-bold text-sm uppercase mb-3 tracking-widest text-slate-900">FROM:</h3>
                         <div className="text-sm text-slate-700 leading-relaxed">
                            <p className="font-bold text-slate-900 text-lg mb-1">{sender.name}</p>
                            <p className="whitespace-pre-line mb-2">{sender.address}</p>
                         </div>
                    </div>
                </div>

                {/* Table */}
                <div className="relative min-h-[300px]">
                    <Watermark />
                    <ReferenceTable />
                </div>

                {/* Footer Section */}
                <div className="mt-auto mb-16">
                     <div className="flex gap-8 items-start">
                         {/* Left: Payment Info or Terms */}
                         <div className="w-[60%] text-sm">
                             {isQuotation ? (
                                <>
                                  <h3 className="font-serif font-bold uppercase mb-2 text-slate-900">Terms & Conditions</h3>
                                  <div className="text-slate-700 space-y-1">
                                    {data.notes ? (
                                        <p className="whitespace-pre-line">{data.notes}</p>
                                    ) : (
                                        <>
                                            <p>1. 50% Advance</p>
                                            <p>2. 50% Post Completion of work</p>
                                        </>
                                    )}
                                  </div>
                                </>
                             ) : (
                                <>
                                   <h3 className="font-serif font-bold uppercase mb-2 text-slate-900">PAYMENT INFORMATION:</h3>
                                   <div className="text-slate-700 space-y-1 font-medium">
                                       {sender.accountName && <p><span className="font-bold">Name:</span> {sender.accountName}</p>}
                                       {sender.accountNumber && <p><span className="font-bold">Account:</span> {sender.accountNumber}</p>}
                                       {sender.pan && <p><span className="font-bold">PAN:</span> {sender.pan}</p>}
                                       {sender.branch && <p><span className="font-bold">Branch:</span> {sender.branch}</p>}
                                       {sender.ifsCode && <p><span className="font-bold">IFS code:</span> {sender.ifsCode}</p>}
                                       {sender.mobile && <p className="mt-2"><span className="font-bold">Mobile No:</span> {sender.mobile}</p>}
                                   </div>
                                </>
                             )}
                         </div>

                         {/* Right: Totals */}
                         <div className="w-[40%]">
                             <div className="border border-slate-900">
                                 <div className="flex justify-between p-3 text-slate-700 font-medium">
                                     <span>Sub Total:</span>
                                     <span>{currencyFormatter.format(subtotal)}</span>
                                 </div>
                                 <div className="p-3 text-white font-bold text-xl flex justify-between items-center" style={{ backgroundColor: theme.colors.primary }}>
                                     <span className="uppercase tracking-widest font-serif">TOTAL:</span>
                                     <span>{currencyFormatter.format(total)}/-</span>
                                 </div>
                             </div>
                         </div>
                     </div>
                </div>

                {/* Website / Bottom Text */}
                <div className="text-center text-xs text-slate-500 mb-8 relative z-20">
                     <p className="flex items-center justify-center gap-1">
                        <span className="text-lg">🌐</span> {sender.website || 'www.example.com'}
                     </p>
                     {!isQuotation && (
                        <p className="absolute left-0 bottom-0 text-[10px]">*not registered under gst</p>
                     )}
                </div>

            </div>
        </div>
      );
  }

  // Fallback for Sidebar/Minimal if selected (keeping existing logic roughly, or we could just remove them if not needed, but safe to keep)
  if (theme.layout === 'sidebar') {
     return (
      <div className={containerClass}>
         {theme.backgroundImage && (
            <div className="absolute inset-0 z-0 overflow-hidden" style={{ opacity: bgOpacity }}>
                <img 
                    src={theme.backgroundImage} 
                    className="w-full h-full object-cover" 
                    style={{ 
                        objectPosition: `${bgX}% ${bgY}%`,
                        transform: `scale(${bgScale})`,
                        transformOrigin: `${bgX}% ${bgY}%`
                    }}
                    alt="" 
                />
            </div>
         )}
         <div className="relative z-10 flex w-full h-full flex-grow">
            <div className="w-[32%] min-h-[297mm] p-8 flex flex-col" style={{ backgroundColor: theme.backgroundImage ? `rgba(0,0,0,${Math.max(0, 0.8 * bgOpacity)})` : (theme.colors.sidebarBg || theme.colors.primary), color: theme.colors.sidebarText || 'white' }}>
                <div className="mb-12"><Logo className="invert brightness-0 origin-top-left" /></div>
                <div className="mb-8">
                <h3 className="text-xs font-bold uppercase tracking-widest mb-4 opacity-70 border-b border-white/20 pb-2">From</h3>
                <p className="font-bold text-lg leading-tight mb-2">{sender.name}</p>
                <p className="text-sm whitespace-pre-line opacity-80">{sender.address}</p>
                <p className="text-sm mt-4 opacity-80">{sender.email}</p>
                <p className="text-sm opacity-80">{sender.website}</p>
                </div>
                <div className="mt-auto">
                {!isQuotation && (
                  <>
                    <h3 className="text-xs font-bold uppercase tracking-widest mb-4 opacity-70 border-b border-white/20 pb-2">Bank Details</h3>
                    <div className="text-sm space-y-2 opacity-90">
                        <p>{sender.accountName}</p>
                        <p>{sender.accountNumber}</p>
                        <p>{sender.ifsCode}</p>
                    </div>
                  </>
                )}
                </div>
            </div>
            <div className="w-[68%] p-10 flex flex-col relative" style={{ backgroundColor: theme.backgroundImage ? `rgba(255,255,255,${0.95 * bgOpacity})` : 'transparent', paddingTop: marginTop, paddingBottom: marginBottom }}>
                <div className="flex justify-between items-start mb-12">
                <div>
                    <h1 className="text-4xl font-bold uppercase tracking-tight text-slate-900 mb-1">{isQuotation ? 'Quotation' : 'Invoice'}</h1>
                    <span className="text-slate-400 text-sm"># {data.invoiceNumber}</span>
                </div>
                <div className="text-right">
                    <p className="text-sm text-slate-500">Date</p>
                    <p className="font-medium">{formatDate(data.date)}</p>
                </div>
                </div>
                <div className="mb-10">
                <h3 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Bill To</h3>
                {client ? (
                    <div>
                        <p className="text-xl font-bold text-slate-800">{client.name}</p>
                        <p className="text-sm text-slate-600 whitespace-pre-line mt-1">{client.address}</p>
                    </div>
                ) : <span className="text-slate-300">Select Client</span>}
                </div>
                <div className="relative flex-grow">
                <Watermark />
                <ReferenceTable />
                </div>
                <div className="mt-8 pt-8 border-t border-slate-200">
                <div className="w-1/2 ml-auto"><div className="w-full">
       <div className="flex justify-between py-2 border-b border-slate-200">
          <span className="text-slate-500 text-sm">Subtotal</span>
          <span className="font-medium">{currencyFormatter.format(subtotal)}</span>
       </div>
       <div 
         className="flex justify-between py-3 mt-2 font-bold text-lg"
         style={{ color: theme.colors.primary }}
       >
          <span>TOTAL</span>
          <span>{currencyFormatter.format(total)}</span>
       </div>
    </div></div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  // Minimal Layout (Simplified)
  return (
        <div className={`${containerClass} p-16`} style={{ paddingTop: marginTop, paddingBottom: marginBottom }}>
           {theme.backgroundImage && (
                <div className="absolute inset-0 z-0 overflow-hidden" style={{ opacity: bgOpacity }}>
                    <img 
                        src={theme.backgroundImage} 
                        className="w-full h-full object-cover" 
                        style={{ 
                            objectPosition: `${bgX}% ${bgY}%`,
                            transform: `scale(${bgScale})`,
                            transformOrigin: `${bgX}% ${bgY}%`
                        }}
                        alt="" 
                    />
                </div>
            )}
           <div className="relative z-10 bg-white/90 p-8 rounded-lg min-h-full flex flex-col flex-grow">
                <div className="text-center mb-12 border-b-2 border-slate-900 pb-8" style={{ borderColor: theme.colors.primary }}>
                    <Logo className="h-16 w-auto mx-auto mb-4 origin-center" />
                    <h1 className="text-3xl font-bold uppercase tracking-widest" style={{ color: theme.colors.primary }}>{sender.name}</h1>
                    <p className="text-xs mt-2 uppercase tracking-wider">{sender.website}</p>
                </div>
                <div className="flex justify-between items-end mb-16">
                    <div>
                        <h2 className="text-4xl font-bold" style={{ color: theme.colors.text }}>{isQuotation ? 'QUOTATION' : 'INVOICE'}</h2>
                        <p className="text-sm mt-1"># {data.invoiceNumber} • {formatDate(data.date)}</p>
                    </div>
                    <div className="text-right max-w-[250px]">
                        <p className="text-xs uppercase font-bold mb-1">Bill To:</p>
                        {client && (
                        <>
                            <p className="font-bold">{client.name}</p>
                            <p className="text-xs whitespace-pre-line">{client.address}</p>
                        </>
                        )}
                    </div>
                </div>
                <div className="relative flex-grow">
                    <Watermark />
                    <ReferenceTable />
                </div>
                <div className="flex justify-between items-start mt-8 pt-8 border-t-2 border-slate-900" style={{ borderColor: theme.colors.primary }}>
                    <div className="w-1/2 text-xs">
                        {!isQuotation && (
                          <>
                            <p className="font-bold uppercase mb-2">Payment Info:</p>
                            <p>{sender.accountName}</p>
                            <p>{sender.accountNumber} • {sender.ifsCode}</p>
                            <p>{sender.branch}</p>
                          </>
                        )}
                    </div>
                    <div className="w-1/3 text-right">
                        <div className="flex justify-between text-lg font-bold">
                        <span>Total</span>
                        <span>{currencyFormatter.format(total)}</span>
                        </div>
                    </div>
                </div>
           </div>
        </div>
  );
};

export default InvoicePreview;

import React, { useState, useRef } from 'react';
import { SenderDetails, Client, InvoiceTheme, DEFAULT_THEMES } from '../types';
import { X, Upload, Save, Trash2, User, CreditCard, Building, Settings as SettingsIcon, LayoutTemplate, Droplets, Plus, Palette, FileJson, Image as ImageIcon, Download, Sliders, Copy } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  senderDetails: SenderDetails;
  onUpdateSender: (details: SenderDetails) => void;
  logo: string | undefined;
  onUpdateLogo: (base64: string) => void;
  invoicePrefix: string;
  onUpdatePrefix: (prefix: string) => void;
  clients: Client[];
  onDeleteClient: (id: string) => void;
  templateId: string;
  onUpdateTemplate: (id: string) => void;
  showWatermark: boolean;
  onToggleWatermark: (show: boolean) => void;
  customThemes?: InvoiceTheme[];
  onAddTheme?: (theme: InvoiceTheme) => void;
  onDeleteTheme?: (id: string) => void;
  onUpdateCustomThemeDetails?: (theme: InvoiceTheme) => void; // New prop for updating existing themes
  customWatermark?: string;
  onUpdateCustomWatermark?: (base64: string) => void;
  watermarkOpacity?: number;
  onUpdateWatermarkOpacity?: (opacity: number) => void;
}

type Tab = 'company' | 'payment' | 'preferences' | 'clients' | 'templates';

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  senderDetails,
  onUpdateSender,
  logo,
  onUpdateLogo,
  invoicePrefix,
  onUpdatePrefix,
  clients,
  onDeleteClient,
  templateId,
  onUpdateTemplate,
  showWatermark,
  onToggleWatermark,
  customThemes = [],
  onAddTheme,
  onDeleteTheme,
  onUpdateCustomThemeDetails,
  customWatermark,
  onUpdateCustomWatermark,
  watermarkOpacity = 10,
  onUpdateWatermarkOpacity
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('company');
  const [localSender, setLocalSender] = useState<SenderDetails>(senderDetails);
  const [localPrefix, setLocalPrefix] = useState(invoicePrefix);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const watermarkInputRef = useRef<HTMLInputElement>(null);
  const themeFileInputRef = useRef<HTMLInputElement>(null);
  const bgImageInputRef = useRef<HTMLInputElement>(null);

  // Template Creator State
  const [isCreatingTheme, setIsCreatingTheme] = useState(false);
  const [newTheme, setNewTheme] = useState<Partial<InvoiceTheme>>({
    name: 'My Custom Theme',
    layout: 'standard',
    font: 'sans',
    colors: { primary: '#3b82f6', accent: '#fbbf24', text: '#1f2937', bg: 'white' }
  });

  // Find the currently active custom theme if it exists
  const activeCustomTheme = customThemes.find(t => t.id === templateId);
  // Get active theme (either custom or default)
  const activeTheme = activeCustomTheme || DEFAULT_THEMES[templateId];

  // Helper to safely get config values
  const getConfig = (key: keyof NonNullable<InvoiceTheme['customConfig']>, def: number) => {
    return activeTheme?.customConfig?.[key] ?? def;
  };

  if (!isOpen) return null;

  const handleSave = () => {
    onUpdateSender(localSender);
    onUpdatePrefix(localPrefix);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, callback: (base64: string) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        callback(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateSenderField = (field: keyof SenderDetails, value: string) => {
    setLocalSender(prev => ({ ...prev, [field]: value }));
  };

  const handleSaveTheme = () => {
    if (!onAddTheme || !newTheme.name) return;

    const themeToSave: InvoiceTheme = {
        id: `custom-${uuidv4()}`,
        name: newTheme.name,
        layout: newTheme.layout as any || 'standard',
        font: newTheme.font as any || 'sans',
        colors: {
            primary: newTheme.colors?.primary || '#000000',
            accent: newTheme.colors?.accent || '#888888',
            text: '#1f2937',
            bg: 'white',
            headerText: newTheme.layout === 'standard' ? 'white' : undefined,
            sidebarBg: newTheme.layout === 'sidebar' ? newTheme.colors?.primary : undefined,
            sidebarText: 'white'
        },
        isCustom: true,
        backgroundImage: newTheme.backgroundImage
    };

    onAddTheme(themeToSave);
    setIsCreatingTheme(false);
    onUpdateTemplate(themeToSave.id);
  };

  const handleCloneTheme = () => {
    if (!onAddTheme) return;
    // Find standard theme to clone
    const standardTheme = DEFAULT_THEMES[templateId];
    if (!standardTheme) return;

    const clonedTheme: InvoiceTheme = {
      ...JSON.parse(JSON.stringify(standardTheme)),
      id: `custom-${uuidv4()}`,
      name: `${standardTheme.name} (Custom)`,
      isCustom: true,
      customConfig: {
        ...standardTheme.customConfig,
        // Initialize defaults if they don't exist
        logoScale: 100,
        logoX: 0,
        logoY: 0,
        watermarkScale: 100,
        watermarkX: 0,
        watermarkY: 0
      }
    };
    onAddTheme(clonedTheme);
    onUpdateTemplate(clonedTheme.id);
  };

  const handleImportTheme = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && onAddTheme) {
        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const imported = JSON.parse(event.target?.result as string);
                if (imported.name && imported.colors) {
                    const themeWithNewId = { ...imported, id: `imported-${uuidv4()}`, isCustom: true };
                    onAddTheme(themeWithNewId);
                    onUpdateTemplate(themeWithNewId.id);
                } else {
                    alert("Invalid theme file format.");
                }
            } catch (err) {
                alert("Failed to parse JSON file.");
            }
        };
        reader.readAsText(file);
    }
  };

  const handleCreateFromImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    handleFileChange(e, (base64) => {
        if (!onAddTheme) return;
        const themeToSave: InvoiceTheme = {
            id: `img-theme-${uuidv4()}`,
            name: 'Custom Image Theme',
            layout: 'standard', // Image backgrounds usually imply a standard overlay
            font: 'sans',
            colors: {
                primary: '#000000',
                accent: '#000000',
                text: '#000000',
                bg: 'transparent'
            },
            isCustom: true,
            backgroundImage: base64,
            customConfig: {
                backgroundOpacity: 100,
                marginTop: 0,
                marginBottom: 0,
                backgroundScale: 100,
                backgroundPositionX: 50,
                backgroundPositionY: 50,
                logoScale: 100,
                logoX: 0,
                logoY: 0,
                watermarkScale: 100,
                watermarkX: 0,
                watermarkY: 0
            }
        };
        onAddTheme(themeToSave);
        onUpdateTemplate(themeToSave.id);
    });
  };

  const updateActiveThemeConfig = (key: keyof NonNullable<InvoiceTheme['customConfig']>, value: number) => {
    if (activeCustomTheme && onUpdateCustomThemeDetails) {
        // Edit existing custom theme
        const updatedTheme = {
            ...activeCustomTheme,
            customConfig: {
                ...activeCustomTheme.customConfig,
                [key]: value
            }
        };
        onUpdateCustomThemeDetails(updatedTheme);
    } else if (!activeCustomTheme && onAddTheme && onUpdateTemplate) {
        // Edit standard theme -> Auto Clone
        const standardTheme = DEFAULT_THEMES[templateId];
        if (standardTheme) {
            const newThemeId = `custom-${uuidv4()}`;
            const clonedTheme: InvoiceTheme = {
                ...JSON.parse(JSON.stringify(standardTheme)),
                id: newThemeId,
                name: `${standardTheme.name} (Custom)`,
                isCustom: true,
                customConfig: {
                    ...standardTheme.customConfig,
                    logoScale: 100, logoX: 0, logoY: 0,
                    watermarkScale: 100, watermarkX: 0, watermarkY: 0,
                    backgroundOpacity: 100, backgroundScale: 100,
                    backgroundPositionX: 50, backgroundPositionY: 50,
                    marginTop: 0, marginBottom: 0,
                    [key]: value // Apply the specific change immediately
                }
            };
            onAddTheme(clonedTheme);
            onUpdateTemplate(newThemeId);
        }
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 print:hidden">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <SettingsIcon size={20} className="text-blue-600" />
            <span>Settings</span>
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-200 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('company')}
            className={`flex-1 py-3 px-2 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'company' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <Building size={16} /> Company
          </button>
          <button 
            onClick={() => setActiveTab('templates')}
            className={`flex-1 py-3 px-2 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'templates' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <LayoutTemplate size={16} /> Templates
          </button>
          <button 
            onClick={() => setActiveTab('payment')}
            className={`flex-1 py-3 px-2 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'payment' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <CreditCard size={16} /> Payment
          </button>
          <button 
            onClick={() => setActiveTab('preferences')}
            className={`flex-1 py-3 px-2 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'preferences' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <SettingsIcon size={16} /> Prefs
          </button>
          <button 
            onClick={() => setActiveTab('clients')}
            className={`flex-1 py-3 px-2 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'clients' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <User size={16} /> Clients
          </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1">
          {activeTab === 'company' && (
            <div className="space-y-4">
              <div className="flex flex-col sm:flex-row items-start gap-6">
                <div className="flex-1 space-y-4 w-full">
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Company Name ("From")</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.name} onChange={e => updateSenderField('name', e.target.value)} />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Website URL</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.website} onChange={e => updateSenderField('website', e.target.value)} />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Company Email</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.email || ''} onChange={e => updateSenderField('email', e.target.value)} />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Address</label>
                     <textarea className="w-full border p-2 rounded text-sm h-24" value={localSender.address} onChange={e => updateSenderField('address', e.target.value)} />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Mobile</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.mobile} onChange={e => updateSenderField('mobile', e.target.value)} />
                   </div>
                </div>

                {/* Logo Upload */}
                <div className="w-full sm:w-1/3">
                  <label className="block text-xs font-medium text-slate-500 mb-1">Company Logo</label>
                  <div 
                    className="border-2 border-dashed border-slate-300 rounded-lg p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-colors h-40 text-center relative overflow-hidden"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    {logo ? (
                      <img src={logo} alt="Logo" className="max-h-24 max-w-full object-contain mb-2 z-10" />
                    ) : (
                      <Upload className="text-slate-300 mb-2 z-10" size={32} />
                    )}
                    <span className="text-xs text-slate-500 z-10">{logo ? 'Click to change' : 'Upload Logo'}</span>
                    <input 
                      type="file" 
                      ref={fileInputRef} 
                      className="hidden" 
                      accept="image/*"
                      onChange={(e) => handleFileChange(e, onUpdateLogo)}
                    />
                  </div>
                  {logo && (
                    <button 
                      onClick={(e) => { e.stopPropagation(); onUpdateLogo(''); }}
                      className="text-red-500 text-xs mt-2 w-full text-center hover:underline"
                    >
                      Remove Logo
                    </button>
                  )}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'templates' && (
            <div className="space-y-6">
               {isCreatingTheme ? (
                 <div className="bg-slate-50 p-5 rounded-xl border border-blue-200 animate-in fade-in zoom-in-95">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="font-bold text-slate-800 flex items-center gap-2">
                           <Palette size={18} className="text-blue-600" />
                           Create Custom Theme
                        </h3>
                        <button onClick={() => setIsCreatingTheme(false)} className="text-slate-400 hover:text-slate-600">
                           <X size={18} />
                        </button>
                    </div>

                    <div className="space-y-4">
                       <div>
                          <label className="block text-xs font-medium text-slate-500 mb-1">Theme Name</label>
                          <input 
                            type="text" 
                            className="w-full border p-2 rounded text-sm focus:ring-2 focus:ring-blue-500 outline-none" 
                            placeholder="My Awesome Theme"
                            value={newTheme.name}
                            onChange={(e) => setNewTheme(prev => ({...prev, name: e.target.value}))}
                          />
                       </div>

                       <div>
                          <label className="block text-xs font-medium text-slate-500 mb-2">Layout Structure</label>
                          <div className="grid grid-cols-3 gap-3">
                             {['standard', 'sidebar', 'minimal'].map(layout => (
                                <button
                                   key={layout}
                                   onClick={() => setNewTheme(prev => ({...prev, layout: layout as any}))}
                                   className={`py-2 px-3 rounded border text-sm capitalize ${newTheme.layout === layout ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-700 border-slate-300 hover:bg-slate-50'}`}
                                >
                                   {layout}
                                </button>
                             ))}
                          </div>
                       </div>

                       <div className="grid grid-cols-2 gap-4">
                          <div>
                             <label className="block text-xs font-medium text-slate-500 mb-1">Primary Color</label>
                             <div className="flex gap-2 items-center">
                                <input 
                                   type="color" 
                                   className="w-10 h-10 rounded cursor-pointer border-0"
                                   value={newTheme.colors?.primary}
                                   onChange={(e) => setNewTheme(prev => ({...prev, colors: {...prev.colors!, primary: e.target.value}}))}
                                />
                                <span className="text-xs text-slate-500 font-mono">{newTheme.colors?.primary}</span>
                             </div>
                          </div>
                          <div>
                             <label className="block text-xs font-medium text-slate-500 mb-1">Accent Color</label>
                             <div className="flex gap-2 items-center">
                                <input 
                                   type="color" 
                                   className="w-10 h-10 rounded cursor-pointer border-0"
                                   value={newTheme.colors?.accent}
                                   onChange={(e) => setNewTheme(prev => ({...prev, colors: {...prev.colors!, accent: e.target.value}}))}
                                />
                                <span className="text-xs text-slate-500 font-mono">{newTheme.colors?.accent}</span>
                             </div>
                          </div>
                       </div>

                       <div>
                          <label className="block text-xs font-medium text-slate-500 mb-2">Typography</label>
                          <select 
                             className="w-full border p-2 rounded text-sm bg-white"
                             value={newTheme.font}
                             onChange={(e) => setNewTheme(prev => ({...prev, font: e.target.value as any}))}
                          >
                             <option value="sans">Sans Serif (Modern)</option>
                             <option value="serif">Serif (Classic)</option>
                             <option value="mono">Monospace (Technical)</option>
                          </select>
                       </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                       <button onClick={() => setIsCreatingTheme(false)} className="px-4 py-2 text-sm text-slate-600 hover:bg-slate-100 rounded">Cancel</button>
                       <button onClick={handleSaveTheme} className="px-6 py-2 text-sm bg-blue-600 text-white rounded hover:bg-blue-700 font-medium">Save Theme</button>
                    </div>
                 </div>
               ) : (
                 <>
                   <div>
                      <label className="block text-sm font-semibold text-slate-700 mb-3">Select Design Template</label>
                      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                         {/* Default Themes */}
                         {Object.values(DEFAULT_THEMES).map(tpl => (
                           <button
                             key={tpl.id}
                             onClick={() => onUpdateTemplate(tpl.id)}
                             className={`relative rounded-lg border-2 p-3 flex flex-col items-center gap-2 transition-all hover:bg-slate-50 ${templateId === tpl.id ? 'border-blue-600 ring-1 ring-blue-600 bg-blue-50' : 'border-slate-200'}`}
                           >
                              <div className="w-12 h-16 rounded shadow-sm" style={{ backgroundColor: tpl.colors.primary }}></div>
                              <span className="text-xs font-medium text-slate-700 text-center">{tpl.name}</span>
                              {templateId === tpl.id && <div className="absolute top-2 right-2 w-2 h-2 bg-blue-600 rounded-full"></div>}
                           </button>
                         ))}

                         {/* Custom Themes */}
                         {customThemes.map(tpl => (
                           <button
                             key={tpl.id}
                             onClick={() => onUpdateTemplate(tpl.id)}
                             className={`relative rounded-lg border-2 p-3 flex flex-col items-center gap-2 transition-all hover:bg-slate-50 group ${templateId === tpl.id ? 'border-blue-600 ring-1 ring-blue-600 bg-blue-50' : 'border-slate-200'}`}
                           >
                              <div className="w-12 h-16 rounded shadow-sm overflow-hidden" style={{ backgroundColor: tpl.colors.primary }}>
                                {tpl.backgroundImage && <img src={tpl.backgroundImage} className="w-full h-full object-cover opacity-50" />}
                              </div>
                              <span className="text-xs font-medium text-slate-700 text-center truncate w-full">{tpl.name}</span>
                              {templateId === tpl.id && <div className="absolute top-2 right-2 w-2 h-2 bg-blue-600 rounded-full"></div>}
                              <div 
                                onClick={(e) => { e.stopPropagation(); onDeleteTheme && onDeleteTheme(tpl.id); }}
                                className="absolute top-1 left-1 bg-white rounded-full p-1 text-red-500 opacity-0 group-hover:opacity-100 hover:bg-red-50 transition-opacity border border-red-100 shadow-sm"
                                title="Delete Theme"
                              >
                                <Trash2 size={12} />
                              </div>
                           </button>
                         ))}

                         {/* Add New Button */}
                         <button
                             onClick={() => setIsCreatingTheme(true)}
                             className="relative rounded-lg border-2 border-dashed border-slate-300 p-3 flex flex-col items-center justify-center gap-2 transition-all hover:border-blue-400 hover:bg-blue-50 text-slate-400 hover:text-blue-500"
                           >
                              <Plus size={24} />
                              <span className="text-xs font-medium text-center">Create Custom</span>
                           </button>
                      </div>

                      {/* Customize Standard Theme Call to Action - Only show if current theme is standard */}
                      {!activeCustomTheme && (
                        <div className="mt-4 p-4 bg-slate-50 border border-slate-200 rounded-lg flex items-center justify-between">
                            <div>
                                <h4 className="text-sm font-bold text-slate-800">Customize this template</h4>
                                <p className="text-xs text-slate-500">Edit positions, colors, and save as your own.</p>
                            </div>
                            <button 
                                onClick={handleCloneTheme}
                                className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-300 rounded-md text-sm font-medium hover:bg-slate-50 hover:text-blue-600 transition-colors shadow-sm"
                            >
                                <Copy size={14} /> Duplicate & Edit
                            </button>
                        </div>
                      )}

                      {/* Adjust Active Custom Template */}
                      <div className="mt-4 p-4 bg-blue-50 border border-blue-100 rounded-lg">
                           <h4 className="text-sm font-bold text-slate-700 mb-3 flex items-center gap-2">
                             <Sliders size={16} className="text-blue-600"/>
                             Adjust Template Layout
                           </h4>

                           {!activeCustomTheme && (
                               <div className="mb-4 bg-blue-100 p-2 rounded text-xs text-blue-700 flex items-start gap-2">
                                   <Copy size={12} className="mt-0.5 shrink-0" />
                                   <span>Adjusting these settings will automatically create a custom copy of this template.</span>
                               </div>
                           )}

                           <div className="space-y-4 h-[250px] overflow-y-auto pr-2">

                             {/* Background Controls */}
                             <div>
                               <div className="flex justify-between text-xs text-slate-500 mb-1 font-semibold bg-blue-100/50 p-1 rounded">Background</div>
                               <div className="space-y-3 pl-2">
                                  <div>
                                    <div className="flex justify-between text-xs text-slate-500 mb-1">
                                        <span>Opacity</span>
                                        <span>{getConfig('backgroundOpacity', 100)}%</span>
                                    </div>
                                    <input 
                                        type="range" min="0" max="100" 
                                        value={getConfig('backgroundOpacity', 100)}
                                        onChange={(e) => updateActiveThemeConfig('backgroundOpacity', Number(e.target.value))}
                                        className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                                    />
                                  </div>
                                  <div>
                                    <div className="flex justify-between text-xs text-slate-500 mb-1">
                                        <span>Scale (Zoom)</span>
                                        <span>{getConfig('backgroundScale', 100)}%</span>
                                    </div>
                                    <input 
                                        type="range" min="50" max="200" 
                                        value={getConfig('backgroundScale', 100)}
                                        onChange={(e) => updateActiveThemeConfig('backgroundScale', Number(e.target.value))}
                                        className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                                    />
                                  </div>
                                  <div className="grid grid-cols-2 gap-2">
                                    <div>
                                        <div className="text-xs text-slate-500 mb-1">Pos X (%)</div>
