};

export default InvoiceDashboard;

import React, { useState } from 'react';
import { InvoiceData, InvoiceTheme, DEFAULT_THEMES } from '../types';

interface InvoicePreviewProps {
  data: InvoiceData;
  logoSrc?: string;
  templateId?: string;
  showWatermark?: boolean;
  customThemes?: InvoiceTheme[];
  customWatermark?: string;
  watermarkOpacity?: number;
}

const InvoicePreview: React.FC<InvoicePreviewProps> = ({ 
  data, 
  logoSrc, 
  templateId = 'classic-blue',
  showWatermark = false,
  customThemes = [],
  customWatermark,
  watermarkOpacity = 10
}) => {
  const [timestamp] = useState(Date.now());

  // Merge default themes with custom ones to find the active theme
  const allThemes = { ...DEFAULT_THEMES };
  customThemes.forEach(t => {
    allThemes[t.id] = t;
  });

  const theme = allThemes[templateId] || DEFAULT_THEMES['classic-blue'];

  // Custom Config Extraction
  const bgOpacity = theme.customConfig?.backgroundOpacity !== undefined ? theme.customConfig.backgroundOpacity / 100 : 1;
  const marginTop = theme.customConfig?.marginTop !== undefined ? `${theme.customConfig.marginTop}mm` : '30mm';
  const marginBottom = theme.customConfig?.marginBottom !== undefined ? `${theme.customConfig.marginBottom}mm` : '20mm';

  // Background Positioning
  const bgScale = theme.customConfig?.backgroundScale !== undefined ? theme.customConfig.backgroundScale / 100 : 1;
  const bgX = theme.customConfig?.backgroundPositionX !== undefined ? theme.customConfig.backgroundPositionX : 50;
  const bgY = theme.customConfig?.backgroundPositionY !== undefined ? theme.customConfig.backgroundPositionY : 50;

  // Logo & Watermark Positioning
  const logoScale = theme.customConfig?.logoScale !== undefined ? theme.customConfig.logoScale / 100 : 1;
  const logoX = theme.customConfig?.logoX ?? 0;
  const logoY = theme.customConfig?.logoY ?? 0;

  const wmScale = theme.customConfig?.watermarkScale !== undefined ? theme.customConfig.watermarkScale / 100 : 1;
  const wmX = theme.customConfig?.watermarkX ?? 0;
  const wmY = theme.customConfig?.watermarkY ?? 0;

  // Helpers
  const currencyFormatter = new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  });

  const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const total = subtotal;
  const isQuotation = data.type === 'quotation';
  const { sender, client, items } = data;

  const formatDate = (d: string) => {
    if (!d) return '';
    const dateObj = new Date(d);
    return dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }).toUpperCase();
  };

  // --- Subcomponents for Rendering ---

  const Logo = ({ className }: { className?: string }) => (
    <div 
      className={className} 
      style={{ 
        transform: `translate(${logoX}mm, ${logoY}mm) scale(${logoScale})`,
        transformOrigin: 'right top',
        display: 'flex',
        justifyContent: 'flex-end'
      }}
    >
      <img 
        src={logoSrc || `/logo.png?t=${timestamp}`}
        alt="Logo" 
        style={{ height: '70px', width: 'auto', objectFit: 'contain' }}
        onError={(e) => {
           e.currentTarget.style.display = 'none';
           document.getElementById(`fallback-${templateId}`)?.classList.remove('hidden');
        }}
      />
      <div id={`fallback-${templateId}`} className="hidden font-bold text-2xl tracking-tighter border-2 border-current px-2 py-1 inline-block" style={{ color: theme.colors.primary }}>
        {sender.name.substring(0,2).toUpperCase()}
      </div>
    </div>
  );

  const Watermark = () => {
    if (!showWatermark) return null;
    const watermarkSrc = customWatermark || logoSrc;

    return (
       <div 
         className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 overflow-hidden" 
         style={{ opacity: watermarkOpacity / 100 }}
       >
         <div style={{ transform: `translate(${wmX}mm, ${wmY}mm) scale(${wmScale})` }}>
           {watermarkSrc ? (
              <img src={watermarkSrc} style={{ width: '500px', objectFit: 'contain' }} alt="Watermark" />
           ) : (
              <svg width="400" height="400" viewBox="0 0 100 100" fill={theme.colors.primary}>
                 <path d="M50 15 L85 75 H15 L50 15Z" stroke={theme.colors.primary} strokeWidth="5" fill="none" />
                 <text x="50" y="50" textAnchor="middle" fontSize="10" fill={theme.colors.primary}>INVOICE</text>
              </svg>
           )}
         </div>
       </div>
    );
  };

  const TopWave = () => (
    <div className="absolute top-0 left-0 right-0 h-40 z-0 overflow-hidden pointer-events-none">
        <svg width="100%" height="160" viewBox="0 0 1440 320" preserveAspectRatio="none">
            <path fill={theme.colors.accent} d="M0,0L1440,0L1440,60C1100,60 1000,120 0,60Z"></path>
            <path fill={theme.colors.primary} d="M0,0L1440,0L1440,40C1100,40 1000,100 0,40Z"></path>
        </svg>
    </div>
  );

  const BottomWave = () => (
    <div className="absolute bottom-0 left-0 right-0 h-40 z-0 overflow-hidden flex items-end pointer-events-none">
         <svg width="100%" height="160" viewBox="0 0 1440 320" preserveAspectRatio="none">
             <path fill={theme.colors.accent} fillOpacity="0.4" d="M0,320L1440,320L1440,220C1000,300 600,200 0,300Z"></path>
             <path fill={theme.colors.primary} d="M0,320L1440,320L1440,300C1000,300 400,280 0,320Z"></path>
             <path fill={theme.colors.accent} d="M0,320L1440,320L1440,280C1200,320 800,320 0,320Z"></path>
         </svg>
    </div>
  );

  const ReferenceTable = () => (
    <div className="relative z-10 w-full mb-4">
      {/* Table Header - Explicit Styles for PDF Engine */}
      <div className="flex w-full" style={{ backgroundColor: theme.colors.primary, color: '#ffffff' }}>
          <div className="py-2.5 px-4 text-left w-[15%] font-serif font-bold uppercase tracking-widest text-[10px]">Item</div>
          <div className="py-2.5 px-4 text-left w-[60%] font-serif font-bold uppercase tracking-widest text-[10px]">Description</div>
          <div className="py-2.5 px-4 text-right w-[25%] font-serif font-bold uppercase tracking-widest text-[10px]">Amount</div>
      </div>

      {/* Table Body - Explicit Styles */}
      <div style={{ borderLeft: '2px solid #000', borderRight: '2px solid #000', borderBottom: '2px solid #000', backgroundColor: 'rgba(255, 255, 255, 0.5)' }} className="relative">
          {items.map((item, index) => (
            <div key={item.id} className="flex w-full" style={{ borderBottom: index === items.length - 1 ? 'none' : '1px solid #94a3b8' }}>
               <div className="py-3 px-4 w-[15%] text-slate-800 font-medium text-center text-xs">{index + 1}.</div>
               <div className="py-3 px-4 w-[60%] text-slate-800 font-medium whitespace-pre-wrap text-xs">{item.description}</div>
               <div className="py-3 px-4 w-[25%] text-right font-bold text-slate-900 text-xs">
                  {currencyFormatter.format(item.quantity * item.unitPrice).replace('₹', '₹ ')}
               </div>
            </div>
          ))}
      </div>
    </div>
  );

  // Use h-full to fill parent container (which is fixed A4 in export)
  const containerClass = `bg-white w-[210mm] min-w-[210mm] min-h-[297mm] mx-auto relative flex flex-col overflow-hidden ${theme.font === 'serif' ? 'font-serif' : theme.font === 'mono' ? 'font-mono' : 'font-sans'}`;

  // Rendering Standard Layout with more explicit attributes for PDF capture
  if (theme.layout === 'standard') {
      return (
        <div className={containerClass} style={{ backgroundColor: '#ffffff', colorAdjust: 'exact', WebkitPrintColorAdjust: 'exact' }}>
            {/* Background Image */}
            {theme.backgroundImage ? (
                <div className="absolute inset-0 z-0 overflow-hidden" style={{ opacity: bgOpacity }}>
                    <img 
                        src={theme.backgroundImage} 
                        style={{ 
                            width: '100%', height: '100%', objectFit: 'cover',
                            objectPosition: `${bgX}% ${bgY}%`,
                            transform: `scale(${bgScale})`,
                            transformOrigin: `${bgX}% ${bgY}%`
                        }}
                        alt="" 
                    />
                </div>
            ) : (
                <>
                  <TopWave />
                  <BottomWave />
                </>
            )}

            <div 
                className="relative z-10 px-12 flex-grow flex flex-col"
                style={{ paddingTop: marginTop, paddingBottom: marginBottom }}
            >
                {/* Header */}
                <div className="flex justify-between items-start mb-6">
                    <div className="mt-4">
                        <h1 className="text-4xl font-serif text-slate-900 mb-2 tracking-tight">
                            {isQuotation ? 'QUOTATION' : 'INVOICE'}
                        </h1>
                        <div className="text-xs text-slate-700 space-y-0.5">
                            <p><span className="font-bold text-slate-900">Document #:</span> {data.invoiceNumber}</p>
                            <p><span className="font-bold text-slate-900">Date:</span> {formatDate(data.date)}</p>
                        </div>
                    </div>
                    <div className="text-right">
                        <Logo />
                    </div>
                </div>

                {/* Addresses */}
                <div className="flex gap-4 mb-8">
                    <div className="w-1/2">
                        <h3 className="font-bold text-[10px] uppercase mb-2 tracking-widest text-slate-900 border-b border-slate-200 pb-1">
                            {isQuotation ? 'QUOTATION TO:' : 'BILL TO:'}
                        </h3>
                        {client ? (
                            <div className="text-slate-800 font-medium">
                                <p className="text-sm font-bold mb-1">{client.name}</p>
                                <p className="whitespace-pre-line text-[10px] leading-normal">{client.address}</p>
                                {client.gstin && <p className="text-[10px] mt-1">GSTIN: {client.gstin}</p>}
                            </div>
                        ) : (
                            <p className="text-slate-300 text-[10px] italic">No client selected.</p>
                        )}
                    </div>
                    <div className="w-1/2 pl-4">
                        <h3 className="font-bold text-[10px] uppercase mb-2 tracking-widest text-slate-900 border-b border-slate-200 pb-1">FROM:</h3>
                         <div className="text-slate-800 font-medium">
                            <p className="text-sm font-bold mb-1">{sender.name}</p>
                            <p className="whitespace-pre-line text-[10px] leading-normal">{sender.address}</p>
                         </div>
                    </div>
                </div>

                {/* Table */}
                <div className="relative mb-6">
                    <Watermark />
                    <ReferenceTable />
                </div>

                {/* Footer and Totals */}
                <div className="mt-auto mb-12">
                     <div className="flex gap-6 items-start">
                         <div className="w-[60%]">
                             <h3 className="font-serif font-bold uppercase mb-2 text-slate-900 text-[10px] tracking-widest">
                                {isQuotation ? 'Terms & Conditions:' : 'Payment Information:'}
                             </h3>
                             <div className="text-slate-700 font-medium space-y-0.5 text-[9px] leading-tight">
                                {isQuotation ? (
                                    <p className="whitespace-pre-line">{data.notes || "1. 50% Advance\n2. Balance on delivery"}</p>
                                ) : (
                                    <>
                                        {sender.accountName && <p>Name: {sender.accountName}</p>}
                                        {sender.accountNumber && <p>Account: {sender.accountNumber}</p>}
                                        {sender.ifsCode && <p>IFS Code: {sender.ifsCode}</p>}
                                        {sender.mobile && <p className="mt-2">Mobile: {sender.mobile}</p>}
                                    </>
                                )}
                             </div>
                         </div>

                         <div className="w-[40%]">
                             <div style={{ border: '2px solid #000', backgroundColor: '#ffffff' }}>
                                 <div className="flex justify-between p-2 text-slate-800 font-bold text-xs">
                                     <span>Sub Total:</span>
                                     <span>{currencyFormatter.format(subtotal).replace('₹', '₹ ')}</span>
                                 </div>
                                 <div className="p-2 text-white font-bold text-base flex justify-between items-center" style={{ backgroundColor: theme.colors.primary, borderTop: '2px solid #000' }}>
                                     <span className="uppercase tracking-widest font-serif text-sm">TOTAL:</span>
                                     <span>{currencyFormatter.format(total).replace('₹', '₹ ')}/-</span>
                                 </div>
                             </div>
                         </div>
                     </div>
                </div>

                {/* Website Footnote */}
                <div className="absolute bottom-6 left-0 right-0 text-center">
                     <p className="flex items-center justify-center gap-2 text-slate-500 text-[10px] font-bold">
                        🌐 {sender.website || 'www.adversitysolutions.in'}
                     </p>
                     {!isQuotation && (
                        <p className="absolute left-12 bottom-0 text-[8px] text-slate-400 font-medium">*not registered under gst</p>
                     )}
                </div>
            </div>
        </div>
      );
  }

  // Simplified Layout for Sidebar and Minimal - using similar logic for robustness
  return (
    <div className={containerClass} style={{ backgroundColor: '#ffffff' }}>
        <div className="p-12 flex flex-col h-full relative z-10">
            <div className="flex justify-between mb-8">
                <Logo />
                <div className="text-right">
                    <h1 className="text-3xl font-bold" style={{ color: theme.colors.primary }}>{isQuotation ? 'QUOTATION' : 'INVOICE'}</h1>
                    <p className="text-sm font-bold text-slate-500">#{data.invoiceNumber}</p>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-8 mb-8">
                <div>
                    <h3 className="text-[10px] font-bold uppercase text-slate-400 mb-2">Billing To</h3>
                    <p className="font-bold text-sm">{client?.name || '---'}</p>
                    <p className="text-[10px] whitespace-pre-line text-slate-600">{client?.address}</p>
                </div>
                <div>
                    <h3 className="text-[10px] font-bold uppercase text-slate-400 mb-2">From</h3>
                    <p className="font-bold text-sm">{sender.name}</p>
                    <p className="text-[10px] whitespace-pre-line text-slate-600">{sender.address}</p>
                </div>
            </div>

            <div className="flex-grow">
                <ReferenceTable />
            </div>

            <div className="flex justify-end mt-8">
                <div className="w-1/3 p-4 rounded-lg" style={{ backgroundColor: theme.colors.primary + '10' }}>
                    <div className="flex justify-between text-xs mb-2">
                        <span className="text-slate-500 font-bold">Subtotal</span>
                        <span className="font-bold">{currencyFormatter.format(subtotal)}</span>
                    </div>
                    <div className="flex justify-between font-bold text-lg pt-2 border-t border-slate-200" style={{ color: theme.colors.primary }}>
                        <span>TOTAL</span>
                        <span>{currencyFormatter.format(total)}</span>
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default InvoicePreview;

import React, { useState, useEffect, useRef } from 'react';
import { 
  InvoiceData, 
  DEFAULT_SENDER, 
  LineItem,
  Client,
  MOCK_CLIENTS,
  SenderDetails,
  InvoiceTheme,
  InvoiceHistoryItem
} from '../types';
import ClientSelector from './ClientSelector';
import InvoicePreview from './InvoicePreview';
import SmartInput from './SmartInput';
import SettingsModal from './SettingsModal';
import HistoryModal from './HistoryModal';
import { Plus, Trash2, Download, Eye, Edit, ArrowLeft, FileText, Settings as SettingsIcon, Mail, LogOut, Loader2, Clock, Save as SaveIcon } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface InvoiceDashboardProps {
  onLogout: () => void;
}

const InvoiceDashboard: React.FC<InvoiceDashboardProps> = ({ onLogout }) => {
  // Load clients from local storage or use mocks
  const [clients, setClients] = useState<Client[]>(() => {
    try {
      const saved = localStorage.getItem('invoicify_clients');
      return saved ? JSON.parse(saved) : MOCK_CLIENTS;
    } catch (e) {
      return MOCK_CLIENTS;
    }
  });

  // Load Sender Details from local storage
  const [senderDetails, setSenderDetails] = useState<SenderDetails>(() => {
    try {
      const saved = localStorage.getItem('invoicify_sender');
      return saved ? JSON.parse(saved) : DEFAULT_SENDER;
    } catch {
      return DEFAULT_SENDER;
    }
  });

  // Load Logo from local storage (Base64)
  const [customLogo, setCustomLogo] = useState<string | undefined>(() => {
    return localStorage.getItem('invoicify_logo') || undefined;
  });

  // Load Custom Watermark
  const [customWatermark, setCustomWatermark] = useState<string | undefined>(() => {
    return localStorage.getItem('invoicify_custom_watermark') || undefined;
  });

  // Load Invoice Prefix
  const [invoicePrefix, setInvoicePrefix] = useState<string>(() => {
    return localStorage.getItem('invoicify_prefix') || 'AS';
  });

  // Load Template ID
  const [templateId, setTemplateId] = useState<string>(() => {
    return localStorage.getItem('invoicify_template') || 'classic-blue';
  });

  // Load Custom Templates
  const [customThemes, setCustomThemes] = useState<InvoiceTheme[]>(() => {
    try {
      const saved = localStorage.getItem('invoicify_custom_themes');
      return saved ? JSON.parse(saved) : [];
    } catch {
      return [];
    }
  });

  // Load Watermark setting
  const [showWatermark, setShowWatermark] = useState<boolean>(() => {
    return localStorage.getItem('invoicify_watermark') === 'true';
  });

  // Load Watermark Opacity
  const [watermarkOpacity, setWatermarkOpacity] = useState<number>(() => {
    const saved = localStorage.getItem('invoicify_watermark_opacity');
    return saved ? parseInt(saved, 10) : 10;
  });

  // Load History
  const [history, setHistory] = useState<InvoiceHistoryItem[]>(() => {
      try {
          const saved = localStorage.getItem('invoicify_history');
          return saved ? JSON.parse(saved) : [];
      } catch {
          return [];
      }
  });

  const [invoiceData, setInvoiceData] = useState<InvoiceData>({
    type: 'invoice',
    invoiceNumber: `${invoicePrefix}00125`,
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    sender: senderDetails,
    client: null,
    items: [
      { id: '1', description: 'Consulting Services', quantity: 1, unitPrice: 0 }
    ],
    notes: ''
  });

  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const exportRef = useRef<HTMLDivElement>(null);

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem('invoicify_clients', JSON.stringify(clients));
  }, [clients]);

  useEffect(() => {
    localStorage.setItem('invoicify_sender', JSON.stringify(senderDetails));
    setInvoiceData(prev => ({ ...prev, sender: senderDetails }));
  }, [senderDetails]);

  useEffect(() => {
    if (customLogo) localStorage.setItem('invoicify_logo', customLogo);
    else localStorage.removeItem('invoicify_logo');
  }, [customLogo]);

  useEffect(() => {
    if (customWatermark) localStorage.setItem('invoicify_custom_watermark', customWatermark);
    else localStorage.removeItem('invoicify_custom_watermark');
  }, [customWatermark]);

  useEffect(() => {
    localStorage.setItem('invoicify_prefix', invoicePrefix);
  }, [invoicePrefix]);

  useEffect(() => {
    localStorage.setItem('invoicify_template', templateId);
  }, [templateId]);

  useEffect(() => {
    localStorage.setItem('invoicify_custom_themes', JSON.stringify(customThemes));
  }, [customThemes]);

  useEffect(() => {
    localStorage.setItem('invoicify_watermark', String(showWatermark));
  }, [showWatermark]);

  useEffect(() => {
    localStorage.setItem('invoicify_watermark_opacity', String(watermarkOpacity));
  }, [watermarkOpacity]);

  useEffect(() => {
      localStorage.setItem('invoicify_history', JSON.stringify(history));
  }, [history]);

  // History Management Logic
  const saveToHistory = (dataToSave: InvoiceData) => {
      setHistory(prev => {
          // Check if invoice number exists
          const index = prev.findIndex(item => item.data.invoiceNumber === dataToSave.invoiceNumber);

          if (index >= 0) {
              // Update existing
              const updatedHistory = [...prev];
              updatedHistory[index] = {
                  ...updatedHistory[index],
                  lastModified: Date.now(),
                  data: dataToSave
              };
              // Move to top
              const item = updatedHistory.splice(index, 1)[0];
              updatedHistory.unshift(item);
              return updatedHistory;
          } else {
              // Add new
              const newItem: InvoiceHistoryItem = {
                  id: uuidv4(),
                  createdAt: Date.now(),
                  lastModified: Date.now(),
                  data: dataToSave
              };
              return [newItem, ...prev];
          }
      });
  };

  const deleteFromHistory = (id: string) => {
      setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadFromHistory = (data: InvoiceData) => {
      setInvoiceData(data);
  };

  // -------------------------

  const addItem = () => {
    const newItem: LineItem = {
      id: Math.random().toString(36).substring(2, 9),
      description: '',
      quantity: 1,
      unitPrice: 0
    };
    setInvoiceData(prev => ({ ...prev, items: [...prev.items, newItem] }));
  };

  const updateItem = (id: string, field: keyof LineItem, value: string | number) => {
    setInvoiceData(prev => ({
      ...prev,
      items: prev.items.map(item => 
        item.id === id ? { ...item, [field]: value } : item
      )
    }));
  };

  const removeItem = (id: string) => {
    setInvoiceData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const addParsedItems = (newItems: LineItem[]) => {
    setInvoiceData(prev => ({
      ...prev,
      items: [...prev.items, ...newItems]
    }));
  };

  const handleAddClient = (newClient: Client) => {
    setClients(prev => [...prev, newClient]);
    setInvoiceData(prev => ({ ...prev, client: newClient }));
  };

  const handleUpdateClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
    if (invoiceData.client && invoiceData.client.id === updatedClient.id) {
      setInvoiceData(prev => ({ ...prev, client: updatedClient }));
    }
  };

  const handleDeleteClient = (id: string) => {
    setClients(prev => prev.filter(c => c.id !== id));
    if (invoiceData.client?.id === id) {
      setInvoiceData(prev => ({ ...prev, client: null }));
    }
  };

  const handleAddTheme = (theme: InvoiceTheme) => {
    setCustomThemes(prev => [...prev, theme]);
  };

  const handleDeleteTheme = (id: string) => {
    setCustomThemes(prev => prev.filter(t => t.id !== id));
    if (templateId === id) {
       setTemplateId('classic-blue');
    }
  };

  const handleUpdateThemeDetails = (updatedTheme: InvoiceTheme) => {
    setCustomThemes(prev => prev.map(t => t.id === updatedTheme.id ? updatedTheme : t));
  };

  const handleExport = () => {
    saveToHistory(invoiceData);
    setIsExporting(true);

    // Give browser time to finish any pending style updates in the hidden container
    setTimeout(() => {
        const element = exportRef.current;
        if (!element) {
            setIsExporting(false);
            return;
        }

        const opt = {
            margin: 0,
            filename: `${invoiceData.invoiceNumber || 'invoice'}.pdf`,
            image: { type: 'jpeg', quality: 1.0 },
            html2canvas: { 
                scale: 2, 
                useCORS: true, 
                logging: false,
                letterRendering: true,
                // A4 is roughly 794px wide at 96dpi. Setting windowWidth forces correct scaling.
                windowWidth: 794,
                backgroundColor: '#ffffff'
            },
            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait', compress: true }
        };

        const html2pdf = (window as any).html2pdf;
        if (html2pdf) {
            html2pdf().set(opt).from(element).save().then(() => {
                setIsExporting(false);
            }).catch((err: any) => {
                console.error("PDF generation failed:", err);
                alert("Export failed. Please try again.");
                setIsExporting(false);
            });
        } else {
            setIsExporting(false);
            window.print();
        }
    }, 800);
  };

  const handleEmail = () => {
    if (!invoiceData.client?.email) {
       alert("Please select a client with an email address first.");
       return;
    }

    // Auto-save to history on email
    saveToHistory(invoiceData);

    const total = invoiceData.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
    const docName = invoiceData.type === 'invoice' ? 'Invoice' : 'Quotation';
    const subject = `${docName} ${invoiceData.invoiceNumber} from ${invoiceData.sender.name}`;
    const body = `Dear ${invoiceData.client.name},\n\nPlease find attached the ${docName.toLowerCase()} #${invoiceData.invoiceNumber}.\n\nTotal Amount: ${total.toLocaleString('en-IN', {style: 'currency', currency: 'INR'})}\n\nRegards,\n${invoiceData.sender.name}`;

    // Alert user about attachment limitation
    if(window.confirm(`Opening email draft to ${invoiceData.client.email}.\n\nNOTE: You must manually attach the PDF after printing/saving it.`)) {
        window.open(`mailto:${invoiceData.client.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`);
    }
  };

  const handleManualSave = () => {
      saveToHistory(invoiceData);
      alert("Invoice saved to history!");
  };

  return (
    <>
      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        senderDetails={senderDetails}
        onUpdateSender={setSenderDetails}
        logo={customLogo}
        onUpdateLogo={setCustomLogo}
        invoicePrefix={invoicePrefix}
        onUpdatePrefix={setInvoicePrefix}
        clients={clients}
        onDeleteClient={handleDeleteClient}
        templateId={templateId}
        onUpdateTemplate={setTemplateId}
        showWatermark={showWatermark}
        onToggleWatermark={setShowWatermark}
        customThemes={customThemes}
        onAddTheme={handleAddTheme}
        onDeleteTheme={handleDeleteTheme}
        onUpdateCustomThemeDetails={handleUpdateThemeDetails}
        customWatermark={customWatermark}
        onUpdateCustomWatermark={setCustomWatermark}
        watermarkOpacity={watermarkOpacity}
        onUpdateWatermarkOpacity={setWatermarkOpacity}
      />

      <HistoryModal 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={history}
        onLoad={loadFromHistory}
        onDelete={deleteFromHistory}
      />

      {/* SCREEN LAYOUT */}
      <div className="min-h-screen flex flex-col md:flex-row font-sans print:hidden">
        {/* Editor Panel (Left) */}
        <div className={`w-full md:w-5/12 lg:w-4/12 bg-white border-r border-slate-200 h-[calc(100vh-60px)] md:h-screen overflow-y-auto ${activeTab === 'preview' ? 'hidden md:block' : ''}`}>

          {/* Navbar for Mobile */}
          <div className="md:hidden flex items-center justify-between p-4 border-b border-slate-200 sticky top-0 bg-white/90 backdrop-blur z-20">
            <span className="font-bold text-lg text-slate-800">Invoicify</span>
            <div className="flex bg-slate-100 rounded-lg p-1">
              <button 
                onClick={() => setActiveTab('edit')} 
                className={`px-3 py-1.5 text-sm rounded-md flex items-center space-x-1 transition-all ${activeTab === 'edit' ? 'bg-white shadow-sm text-slate-800 font-medium' : 'text-slate-500'}`}
              >
                <Edit size={14} />
                <span>Edit</span>
              </button>
              <button 
                onClick={() => setActiveTab('preview')} 
                className={`px-3 py-1.5 text-sm rounded-md flex items-center space-x-1 transition-all ${activeTab === 'preview' ? 'bg-white shadow-sm text-slate-800 font-medium' : 'text-slate-500'}`}
              >
                <Eye size={14} />
                <span>View</span>
              </button>
            </div>
          </div>

          <div className="p-6 pb-20">
            <div className="mb-8 hidden md:block flex justify-between items-center">
              <div>
                <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                   Invoicify
                </h1>
                <p className="text-slate-500 text-sm mt-1">Generate standard invoices</p>
              </div>
              <div className="flex items-center gap-2">
                <button 
                  onClick={() => setIsHistoryOpen(true)}
                  className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                  title="History"
                >
                   <Clock size={20} />
                </button>
                <button 
                  onClick={() => setIsSettingsOpen(true)}
                  className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
                  title="Settings"
                >
                  <SettingsIcon size={20} />
                </button>
                <button 
                  onClick={onLogout}
                  className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                  title="Logout"
                >
                  <LogOut size={20} />
                </button>
              </div>
            </div>

            <div className="md:hidden mb-6 flex justify-between">
               <button 
                onClick={onLogout}
                className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-red-500 px-3 py-2"
              >
                <LogOut size={16} />
                <span>Exit</span>
              </button>
               <div className="flex gap-2">
                 <button 
                  onClick={() => setIsHistoryOpen(true)}
                  className="flex items-center gap-2 text-sm font-medium text-slate-600 bg-slate-100 px-3 py-2 rounded-lg"
                 >
                   <Clock size={16} />
                 </button>
                 <button 
                  onClick={() => setIsSettingsOpen(true)}
                  className="flex items-center gap-2 text-sm font-medium text-slate-600 bg-slate-100 px-3 py-2 rounded-lg"
                 >
                   <SettingsIcon size={16} />
                   <span>Config</span>
                 </button>
               </div>
            </div>

            <section className="mb-8">
              <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Client Details (Bill To)</h2>
              <ClientSelector 
                selectedClient={invoiceData.client} 
                onSelectClient={(client) => setInvoiceData(prev => ({ ...prev, client }))} 
                clients={clients}
                onAddClient={handleAddClient}
                onUpdateClient={handleUpdateClient}
              />
            </section>

            <section className="mb-8">
               <div className="flex justify-between items-center mb-4">
                <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Items</h2>
              </div>

              <SmartInput onItemsParsed={addParsedItems} />

              <div className="space-y-4">
                {invoiceData.items.map((item, index) => (
                  <div key={item.id} className="bg-slate-50 p-4 rounded-lg border border-slate-200 group relative transition-all hover:shadow-sm">
                    <div className="absolute right-2 top-2 opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => removeItem(item.id)} className="bg-white text-slate-400 hover:text-red-500 p-2 rounded-full shadow-sm border border-slate-100">
                        <Trash2 size={16} />
                      </button>
                    </div>
                    <div className="mb-3 pr-8">
                      <label className="block text-xs font-medium text-slate-500 mb-1">Description</label>
                      <input
                        type="text"
                        value={item.description}
                        onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                        className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                        placeholder="Item description"
                      />
                    </div>
                    <div className="flex space-x-3">
                      <div className="w-1/4">
                         <label className="block text-xs font-medium text-slate-500 mb-1">Qty</label>
                         <input
                          type="number"
                          inputMode="numeric"
                          min="1"
                          value={item.quantity}
                          onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                        />
                      </div>
                      <div className="w-1/3">
                        <label className="block text-xs font-medium text-slate-500 mb-1">Cost</label>
                        <input
                          type="number"
                          inputMode="decimal"
                          min="0"
                          step="0.01"
                          value={item.unitPrice}
                          onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                        />
                      </div>
                       <div className="w-1/3">
                        <label className="block text-xs font-medium text-slate-500 mb-1">Total</label>
                        <div className="w-full bg-slate-100 border border-slate-200 rounded px-3 py-2 text-sm text-slate-600 font-medium truncate">
                          ₹{(item.quantity * item.unitPrice).toLocaleString('en-IN')}
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <button 
                onClick={addItem}
                className="mt-4 w-full py-3 md:py-2 border border-dashed border-slate-300 rounded-lg text-slate-500 hover:border-slate-400 hover:text-slate-600 hover:bg-slate-50 transition-colors flex items-center justify-center space-x-2 text-sm active:bg-slate-100"
              >
                <Plus size={16} />
                <span>Add Item</span>
              </button>
            </section>

            <section className="mb-8">
               <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Info</h2>
               <div className="space-y-4">
                 <div>
                   <label className="block text-xs font-medium text-slate-500 mb-1">Document Type</label>
                   <div className="flex bg-slate-100 p-1 rounded-lg">
                      <button 
                        onClick={() => setInvoiceData(prev => ({...prev, type: 'invoice'}))}
                        className={`flex-1 flex items-center justify-center space-x-2 py-2 text-sm rounded-md transition-all ${invoiceData.type === 'invoice' ? 'bg-white shadow text-slate-900 font-medium' : 'text-slate-500'}`}
                      >
                         <FileText size={14} />
                         <span>Invoice</span>
                      </button>
                      <button 
                        onClick={() => setInvoiceData(prev => ({...prev, type: 'quotation'}))}
                        className={`flex-1 flex items-center justify-center space-x-2 py-2 text-sm rounded-md transition-all ${invoiceData.type === 'quotation' ? 'bg-white shadow text-slate-900 font-medium' : 'text-slate-500'}`}
                      >
                         <FileText size={14} />
                         <span>Quotation</span>
                      </button>
                   </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">
                        {invoiceData.type === 'invoice' ? 'Invoice #' : 'Quotation #'}
                     </label>
                     <input 
                        type="text" 
                        value={invoiceData.invoiceNumber}
                        onChange={(e) => setInvoiceData(prev => ({...prev, invoiceNumber: e.target.value}))}
                        className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                     />
                   </div>
                   <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Date</label>
                     <input 
                        type="date" 
                        value={invoiceData.date}
                        onChange={(e) => setInvoiceData(prev => ({...prev, date: e.target.value}))}
                        className="w-full bg-white border border-slate-200 rounded px-3 py-2 text-sm focus:outline-none focus:border-blue-500"
                     />
                   </div>
                 </div>
               </div>
            </section>
          </div>
        </div>

        {/* Preview Panel (Right) */}
        <div className={`w-full md:w-7/12 lg:w-8/12 bg-slate-100 h-[calc(100vh-60px)] md:h-screen overflow-y-auto relative ${activeTab === 'edit' ? 'hidden md:block' : ''}`}>

          {/* Header Actions */}
          <div className="sticky top-0 z-10 p-4 flex justify-between items-center pointer-events-none">
             {/* Back Button (Mobile Only) */}
             <div className="pointer-events-auto">
                <button 
                  onClick={() => setActiveTab('edit')}
                  className="md:hidden bg-white/90 backdrop-blur text-slate-700 px-4 py-2.5 rounded-full shadow-lg border border-slate-200 flex items-center space-x-2 font-medium active:scale-95"
                >
                  <ArrowLeft size={18} />
                  <span>Back</span>
                </button>
             </div>

             {/* Action Buttons */}
             <div className="pointer-events-auto flex space-x-3">
                <button 
                  onClick={handleManualSave}
                  className="bg-white text-slate-600 px-4 py-2.5 rounded-full shadow-lg border border-slate-200 hover:bg-slate-50 transition-all flex items-center space-x-2 font-medium active:scale-95"
                  title="Save Draft"
                >
                  <SaveIcon size={18} />
                </button>
                <button 
                  onClick={handleEmail}
                  className="bg-white text-slate-700 px-5 py-2.5 rounded-full shadow-lg border border-slate-200 hover:bg-slate-50 transition-all flex items-center space-x-2 font-medium active:scale-95"
                >
                  <Mail size={18} />
                  <span>Email</span>
                </button>
                <button 
                  onClick={handleExport}
                  disabled={isExporting}
                  className="bg-slate-900 text-white px-5 py-2.5 rounded-full shadow-lg hover:bg-slate-800 hover:shadow-xl transition-all flex items-center space-x-2 font-medium active:scale-95 disabled:bg-slate-600 disabled:cursor-not-allowed"
                >
                  {isExporting ? <Loader2 size={18} className="animate-spin" /> : <Download size={18} />}
                  <span>{isExporting ? 'Generating...' : 'PDF'}</span>
                </button>
             </div>
          </div>

          <div className="p-2 md:p-8 lg:p-12 flex justify-center items-start min-h-full overflow-hidden pb-20">
             <div className="transform scale-[0.42] sm:scale-[0.6] md:scale-[0.85] lg:scale-100 origin-top shadow-2xl transition-transform duration-300 bg-white">
                <InvoicePreview 
                  data={invoiceData} 
                  logoSrc={customLogo} 
                  templateId={templateId}
                  showWatermark={showWatermark}
                  customThemes={customThemes}
                  customWatermark={customWatermark}
                  watermarkOpacity={watermarkOpacity}
                />
             </div>
          </div>
        </div>
      </div>

      {/* 
        OFF-SCREEN EXPORT CONTAINER
        Positioned off-screen to remain in DOM for capture.
        Strict A4 sizing and overflow hidden to enforce 1-page output.
      */}
      {/* Fix: Changed zindex to zIndex as per React style property requirements */}
      <div id="export-root" style={{ position: 'fixed', left: '-2000mm', top: 0, width: '210mm', height: '297mm', zIndex: -1 }}>
        <div ref={exportRef} className="bg-white overflow-hidden" style={{ width: '210mm', height: '296mm' }}>
            <InvoicePreview 
                data={invoiceData} 
                logoSrc={customLogo} 
                templateId={templateId}
                showWatermark={showWatermark}
                customThemes={customThemes}
                customWatermark={customWatermark}
                watermarkOpacity={watermarkOpacity}
            />
        </div>
      </div>
    </>
  );
};

