import React, { useState, useRef } from 'react';
import { SenderDetails, Client, InvoiceTheme, DEFAULT_THEMES } from '../types';
import { X, Upload, Save, Trash2, User, CreditCard, Building, Settings as SettingsIcon, LayoutTemplate, Droplets, Plus, Palette, FileJson, Image as ImageIcon, Download, Sliders, Copy } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  senderDetails: SenderDetails;
  onUpdateSender: (details: SenderDetails) => void;
  logo: string | undefined;
  onUpdateLogo: (base64: string) => void;
  invoicePrefix: string;
  onUpdatePrefix: (prefix: string) => void;
  clients: Client[];
  onDeleteClient: (id: string) => void;
  templateId: string;
  onUpdateTemplate: (id: string) => void;
  showWatermark: boolean;
  onToggleWatermark: (show: boolean) => void;
  customThemes?: InvoiceTheme[];
  onAddTheme?: (theme: InvoiceTheme) => void;
  onDeleteTheme?: (id: string) => void;
  onUpdateCustomThemeDetails?: (theme: InvoiceTheme) => void;
  customWatermark?: string;
  onUpdateCustomWatermark?: (base64: string) => void;
  watermarkOpacity?: number;
  onUpdateWatermarkOpacity?: (opacity: number) => void;
}

type Tab = 'company' | 'payment' | 'preferences' | 'clients' | 'templates';

const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  senderDetails,
  onUpdateSender,
  logo,
  onUpdateLogo,
  invoicePrefix,
  onUpdatePrefix,
  clients,
  onDeleteClient,
  templateId,
  onUpdateTemplate,
  showWatermark,
  onToggleWatermark,
  customThemes = [],
  onAddTheme,
  onDeleteTheme,
  onUpdateCustomThemeDetails,
  customWatermark,
  onUpdateCustomWatermark,
  watermarkOpacity = 10,
  onUpdateWatermarkOpacity
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('company');
  const [localSender, setLocalSender] = useState<SenderDetails>(senderDetails);
  const [localPrefix, setLocalPrefix] = useState(invoicePrefix);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const watermarkInputRef = useRef<HTMLInputElement>(null);
  const themeFileInputRef = useRef<HTMLInputElement>(null);
  const bgImageInputRef = useRef<HTMLInputElement>(null);

  const [isCreatingTheme, setIsCreatingTheme] = useState(false);
  const [newTheme, setNewTheme] = useState<Partial<InvoiceTheme>>({
    name: 'My Custom Theme',
    layout: 'standard',
    font: 'sans',
    colors: { primary: '#3b82f6', accent: '#fbbf24', text: '#1f2937', bg: 'white', tableColor: '#3b82f6' }
  });

  const activeCustomTheme = customThemes.find(t => t.id === templateId);
  const activeTheme = activeCustomTheme || DEFAULT_THEMES[templateId];

  const getConfig = (key: keyof NonNullable<InvoiceTheme['customConfig']>, def: number) => {
    return activeTheme?.customConfig?.[key] ?? def;
  };

  if (!isOpen) return null;

  const handleSave = () => {
    onUpdateSender(localSender);
    onUpdatePrefix(localPrefix);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, callback: (base64: string) => void) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        callback(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const updateSenderField = (field: keyof SenderDetails, value: string) => {
    setLocalSender(prev => ({ ...prev, [field]: value }));
  };

  const handleSaveTheme = () => {
    if (!onAddTheme || !newTheme.name) return;

    const themeToSave: InvoiceTheme = {
        id: `custom-${uuidv4()}`,
        name: newTheme.name,
        layout: newTheme.layout as any || 'standard',
        font: newTheme.font as any || 'sans',
        colors: {
            primary: newTheme.colors?.primary || '#000000',
            accent: newTheme.colors?.accent || '#888888',
            text: '#1f2937',
            bg: 'white',
            tableColor: newTheme.colors?.tableColor || newTheme.colors?.primary || '#000000',
            headerText: newTheme.layout === 'standard' ? 'white' : undefined,
            sidebarBg: newTheme.layout === 'sidebar' ? newTheme.colors?.primary : undefined,
            sidebarText: 'white'
        },
        isCustom: true,
        backgroundImage: newTheme.backgroundImage
    };

    onAddTheme(themeToSave);
    setIsCreatingTheme(false);
    onUpdateTemplate(themeToSave.id);
  };

  const handleCloneTheme = () => {
    if (!onAddTheme) return;
    const standardTheme = DEFAULT_THEMES[templateId];
    if (!standardTheme) return;

    const clonedTheme: InvoiceTheme = {
      ...JSON.parse(JSON.stringify(standardTheme)),
      id: `custom-${uuidv4()}`,
      name: `${standardTheme.name} (Custom)`,
      isCustom: true,
      colors: {
          ...standardTheme.colors,
          tableColor: standardTheme.colors.tableColor || standardTheme.colors.primary
      }
    };
    onAddTheme(clonedTheme);
    onUpdateTemplate(clonedTheme.id);
  };

  const updateActiveThemeConfig = (key: keyof NonNullable<InvoiceTheme['customConfig']>, value: number) => {
    if (activeCustomTheme && onUpdateCustomThemeDetails) {
        onUpdateCustomThemeDetails({
            ...activeCustomTheme,
            customConfig: {
                ...activeCustomTheme.customConfig,
                [key]: value
            }
        });
    } else if (!activeCustomTheme && onAddTheme && onUpdateTemplate) {
        const standardTheme = DEFAULT_THEMES[templateId];
        if (standardTheme) {
            const newThemeId = `custom-${uuidv4()}`;
            onAddTheme({
                ...JSON.parse(JSON.stringify(standardTheme)),
                id: newThemeId,
                name: `${standardTheme.name} (Custom)`,
                isCustom: true,
                customConfig: {
                    ...standardTheme.customConfig,
                    [key]: value
                }
            });
            onUpdateTemplate(newThemeId);
        }
    }
  };

  const updateActiveThemeColor = (key: keyof InvoiceTheme['colors'], value: string) => {
    if (activeCustomTheme && onUpdateCustomThemeDetails) {
        onUpdateCustomThemeDetails({
            ...activeCustomTheme,
            colors: {
                ...activeCustomTheme.colors,
                [key]: value
            }
        });
    } else if (!activeCustomTheme && onAddTheme && onUpdateTemplate) {
        const standardTheme = DEFAULT_THEMES[templateId];
        if (standardTheme) {
            const newThemeId = `custom-${uuidv4()}`;
            onAddTheme({
                ...JSON.parse(JSON.stringify(standardTheme)),
                id: newThemeId,
                name: `${standardTheme.name} (Custom)`,
                isCustom: true,
                colors: {
                    ...standardTheme.colors,
                    [key]: value
                }
            });
            onUpdateTemplate(newThemeId);
        }
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 print:hidden">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <SettingsIcon size={20} className="text-blue-600" />
            <span>Settings</span>
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        <div className="flex border-b border-slate-200 overflow-x-auto">
          {['company', 'templates', 'payment', 'preferences', 'clients'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as Tab)}
              className={`flex-1 py-3 px-2 text-sm font-medium capitalize border-b-2 transition-colors whitespace-nowrap ${activeTab === tab ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              {tab}
            </button>
          ))}
        </div>

        <div className="p-6 overflow-y-auto flex-1">
          {activeTab === 'company' && (
            <div className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="col-span-full">
                     <label className="block text-xs font-medium text-slate-500 mb-1">Company Name</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.name} onChange={e => updateSenderField('name', e.target.value)} />
                  </div>
                  <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Website</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.website} onChange={e => updateSenderField('website', e.target.value)} />
                  </div>
                  <div>
                     <label className="block text-xs font-medium text-slate-500 mb-1">Email</label>
                     <input type="text" className="w-full border p-2 rounded text-sm" value={localSender.email} onChange={e => updateSenderField('email', e.target.value)} />
                  </div>
                  <div className="col-span-full">
                     <label className="block text-xs font-medium text-slate-500 mb-1">Address</label>
                     <textarea className="w-full border p-2 rounded text-sm h-20" value={localSender.address} onChange={e => updateSenderField('address', e.target.value)} />
                  </div>
                  <div 
                    className="col-span-full border-2 border-dashed border-slate-300 rounded-lg p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-colors h-32"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    {logo ? <img src={logo} alt="Logo" className="max-h-20 max-w-full object-contain" /> : <Upload className="text-slate-300" size={24} />}
                    <span className="text-xs text-slate-500 mt-2">{logo ? 'Click to change' : 'Upload Logo'}</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => handleFileChange(e, onUpdateLogo)} />
                  </div>
              </div>
            </div>
          )}

          {activeTab === 'templates' && (
            <div className="space-y-6">
               {isCreatingTheme ? (
                 <div className="bg-slate-50 p-5 rounded-xl border border-blue-200">
                    <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2"><Palette size={18}/> Create Custom Theme</h3>
                    <div className="space-y-4">
                       <input 
                         type="text" 
                         className="w-full border p-2 rounded text-sm" 
                         placeholder="Theme Name"
                         value={newTheme.name}
                         onChange={(e) => setNewTheme(prev => ({...prev, name: e.target.value}))}
                       />
                       <div className="grid grid-cols-2 gap-4">
                          <div>
                             <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1">Primary Color</label>
                             <input type="color" className="w-full h-10 rounded cursor-pointer border" value={newTheme.colors?.primary} onChange={(e) => setNewTheme(prev => ({...prev, colors: {...prev.colors!, primary: e.target.value}}))} />
                          </div>
                          <div>
                             <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1">Table Color</label>
                             <input type="color" className="w-full h-10 rounded cursor-pointer border" value={newTheme.colors?.tableColor} onChange={(e) => setNewTheme(prev => ({...prev, colors: {...prev.colors!, tableColor: e.target.value}}))} />
                          </div>
                       </div>
                    </div>
                    <div className="flex justify-end gap-3 mt-6">
                       <button onClick={() => setIsCreatingTheme(false)} className="text-sm text-slate-500">Cancel</button>
                       <button onClick={handleSaveTheme} className="px-4 py-2 bg-blue-600 text-white rounded text-sm font-bold">Create</button>
                    </div>
                 </div>
               ) : (
                 <>
                   <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                      {Object.values(DEFAULT_THEMES).concat(customThemes).map(tpl => (
                        <button
                          key={tpl.id}
                          onClick={() => onUpdateTemplate(tpl.id)}
                          className={`relative rounded-lg border-2 p-3 flex flex-col items-center gap-2 transition-all ${templateId === tpl.id ? 'border-blue-600 bg-blue-50' : 'border-slate-200'}`}
                        >
                           <div className="w-full h-8 rounded" style={{ backgroundColor: tpl.colors.primary }}></div>
                           <span className="text-[10px] font-bold truncate w-full">{tpl.name}</span>
                        </button>
                      ))}
                      <button onClick={() => setIsCreatingTheme(true)} className="border-2 border-dashed border-slate-300 rounded-lg p-3 flex flex-col items-center justify-center text-slate-400 hover:border-blue-500 hover:text-blue-500">
                         <Plus size={20} />
                         <span className="text-[10px] font-bold">Custom</span>
                      </button>
                   </div>

                   <div className="p-4 bg-slate-50 border rounded-lg space-y-4">
                      <h4 className="text-xs font-bold text-slate-700 flex items-center gap-2"><Sliders size={14}/> Customize Active Template</h4>
                      <div className="grid grid-cols-2 gap-4">
                         <div>
                            <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1">Table Color</label>
                            <input 
                              type="color" 
                              className="w-full h-8 rounded cursor-pointer border" 
                              value={activeTheme.colors.tableColor || activeTheme.colors.primary} 
                              onChange={(e) => updateActiveThemeColor('tableColor', e.target.value)} 
                            />
                         </div>
                         <div>
                            <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1">Primary Color</label>
                            <input 
                              type="color" 
                              className="w-full h-8 rounded cursor-pointer border" 
                              value={activeTheme.colors.primary} 
                              onChange={(e) => updateActiveThemeColor('primary', e.target.value)} 
                            />
                         </div>
                      </div>
                      <div className="space-y-3 pt-2">
                        <label className="block text-[10px] font-bold uppercase text-slate-400">Layout Adjustments</label>
                        <div className="grid grid-cols-2 gap-2">
                           {[['Logo X', 'logoX'], ['Logo Y', 'logoY'], ['Margin T', 'marginTop'], ['Margin B', 'marginBottom']].map(([label, key]) => (
                             <div key={key}>
                               <span className="text-[10px] text-slate-500">{label} (mm)</span>
                               <input 
                                 type="number" 
                                 className="w-full border rounded p-1 text-xs" 
                                 value={getConfig(key as any, 0)} 
                                 onChange={(e) => updateActiveThemeConfig(key as any, Number(e.target.value))} 
                               />
                             </div>
                           ))}
                        </div>
                      </div>
                   </div>
                 </>
               )}
            </div>
          )}

          {/* ... other tabs ... */}
        </div>

        <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-end space-x-3">
          <button onClick={onClose} className="px-4 py-2 text-sm font-medium text-slate-600">Cancel</button>
          <button onClick={handleSave} className="px-6 py-2 bg-slate-900 text-white rounded-lg text-sm font-bold">Save Settings</button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState } from 'react';
import { InvoiceData, InvoiceTheme, DEFAULT_THEMES } from '../types';

interface InvoicePreviewProps {
  data: InvoiceData;
  logoSrc?: string;
  templateId?: string;
  showWatermark?: boolean;
  customThemes?: InvoiceTheme[];
  customWatermark?: string;
  watermarkOpacity?: number;
}

const InvoicePreview: React.FC<InvoicePreviewProps> = ({ 
  data, 
  logoSrc, 
  templateId = 'classic-blue',
  showWatermark = false,
  customThemes = [],
  customWatermark,
  watermarkOpacity = 10
}) => {
  const [timestamp] = useState(Date.now());

  const allThemes = { ...DEFAULT_THEMES };
  customThemes.forEach(t => {
    allThemes[t.id] = t;
  });

  const theme = allThemes[templateId] || DEFAULT_THEMES['classic-blue'];
  const tableColor = theme.colors.tableColor || theme.colors.primary;

  const bgOpacity = theme.customConfig?.backgroundOpacity !== undefined ? theme.customConfig.backgroundOpacity / 100 : 1;
  const marginTop = theme.customConfig?.marginTop !== undefined ? `${theme.customConfig.marginTop}mm` : '30mm';
  const marginBottom = theme.customConfig?.marginBottom !== undefined ? `${theme.customConfig.marginBottom}mm` : '20mm';

  const bgScale = theme.customConfig?.backgroundScale !== undefined ? theme.customConfig.backgroundScale / 100 : 1;
  const bgX = theme.customConfig?.backgroundPositionX !== undefined ? theme.customConfig.backgroundPositionX : 50;
  const bgY = theme.customConfig?.backgroundPositionY !== undefined ? theme.customConfig.backgroundPositionY : 50;

  const logoScale = theme.customConfig?.logoScale !== undefined ? theme.customConfig.logoScale / 100 : 1;
  const logoX = theme.customConfig?.logoX ?? 0;
  const logoY = theme.customConfig?.logoY ?? 0;

  const wmScale = theme.customConfig?.watermarkScale !== undefined ? theme.customConfig.watermarkScale / 100 : 1;
  const wmX = theme.customConfig?.watermarkX ?? 0;
  const wmY = theme.customConfig?.watermarkY ?? 0;

  const currencyFormatter = new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  });

  const subtotal = data.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const total = subtotal;
  const isQuotation = data.type === 'quotation';
  const { sender, client, items } = data;

  const formatDate = (d: string) => {
    if (!d) return '';
    const dateObj = new Date(d);
    return dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }).toUpperCase();
  };

  const Logo = ({ className }: { className?: string }) => (
    <div 
      className={className} 
      style={{ 
        transform: `translate(${logoX}mm, ${logoY}mm) scale(${logoScale})`,
        transformOrigin: 'right top',
        display: 'flex',
        justifyContent: 'flex-end'
      }}
    >
      <img 
        src={logoSrc || `/logo.png?t=${timestamp}`}
        alt="Logo" 
        style={{ height: '70px', width: 'auto', objectFit: 'contain' }}
        onError={(e) => {
           e.currentTarget.style.display = 'none';
           document.getElementById(`fallback-${templateId}`)?.classList.remove('hidden');
        }}
      />
      <div id={`fallback-${templateId}`} className="hidden font-bold text-2xl tracking-tighter border-2 border-current px-2 py-1 inline-block" style={{ color: theme.colors.primary }}>
        {sender.name.substring(0,2).toUpperCase()}
      </div>
    </div>
  );

  const Watermark = () => {
    if (!showWatermark) return null;
    const watermarkSrc = customWatermark || logoSrc;

    return (
       <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 overflow-hidden" style={{ opacity: watermarkOpacity / 100 }}>
         <div style={{ transform: `translate(${wmX}mm, ${wmY}mm) scale(${wmScale})` }}>
           {watermarkSrc ? (
              <img src={watermarkSrc} style={{ width: '500px', objectFit: 'contain' }} alt="Watermark" />
           ) : (
              <svg width="400" height="400" viewBox="0 0 100 100" fill={tableColor}>
                 <path d="M50 15 L85 75 H15 L50 15Z" stroke={tableColor} strokeWidth="5" fill="none" />
                 <text x="50" y="50" textAnchor="middle" fontSize="10" fill={tableColor}>INVOICE</text>
              </svg>
           )}
         </div>
       </div>
    );
  };

  const TopWave = () => (
    <div className="absolute top-0 left-0 right-0 h-40 z-0 overflow-hidden pointer-events-none">
        <svg width="100%" height="160" viewBox="0 0 1440 320" preserveAspectRatio="none">
            <path fill={theme.colors.accent} d="M0,0L1440,0L1440,60C1100,60 1000,120 0,60Z"></path>
            <path fill={theme.colors.primary} d="M0,0L1440,0L1440,40C1100,40 1000,100 0,40Z"></path>
        </svg>
    </div>
  );

  const BottomWave = () => (
    <div className="absolute bottom-0 left-0 right-0 h-40 z-0 overflow-hidden flex items-end pointer-events-none">
         <svg width="100%" height="160" viewBox="0 0 1440 320" preserveAspectRatio="none">
             <path fill={theme.colors.accent} fillOpacity="0.4" d="M0,320L1440,320L1440,220C1000,300 600,200 0,300Z"></path>
             <path fill={theme.colors.primary} d="M0,320L1440,320L1440,300C1000,300 400,280 0,320Z"></path>
             <path fill={theme.colors.accent} d="M0,320L1440,320L1440,280C1200,320 800,320 0,320Z"></path>
         </svg>
    </div>
  );

  const ReferenceTable = () => (
    <div className="relative z-10 w-full mb-4">
      <div className="flex w-full" style={{ backgroundColor: tableColor, color: '#ffffff' }}>
          <div className="py-2.5 px-4 text-left w-[15%] font-serif font-bold uppercase tracking-widest text-[10px]">Item</div>
          <div className="py-2.5 px-4 text-left w-[60%] font-serif font-bold uppercase tracking-widest text-[10px]">Description</div>
          <div className="py-2.5 px-4 text-right w-[25%] font-serif font-bold uppercase tracking-widest text-[10px]">Amount</div>
      </div>
      <div style={{ borderLeft: `2px solid ${tableColor}`, borderRight: `2px solid ${tableColor}`, borderBottom: `2px solid ${tableColor}`, backgroundColor: 'rgba(255, 255, 255, 0.5)' }} className="relative">
          {items.map((item, index) => (
            <div key={item.id} className="flex w-full" style={{ borderBottom: index === items.length - 1 ? 'none' : '1px solid #94a3b8' }}>
               <div className="py-3 px-4 w-[15%] text-slate-800 font-medium text-center text-xs">{index + 1}.</div>
               <div className="py-3 px-4 w-[60%] text-slate-800 font-medium whitespace-pre-wrap text-xs">{item.description}</div>
               <div className="py-3 px-4 w-[25%] text-right font-bold text-slate-900 text-xs">
                  {currencyFormatter.format(item.quantity * item.unitPrice).replace('₹', '₹ ')}
               </div>
            </div>
          ))}
      </div>
    </div>
  );

  const containerClass = `bg-white w-[210mm] min-w-[210mm] min-h-[297mm] mx-auto relative flex flex-col overflow-hidden ${theme.font === 'serif' ? 'font-serif' : theme.font === 'mono' ? 'font-mono' : 'font-sans'}`;

  if (theme.layout === 'standard') {
      return (
        <div className={containerClass} style={{ backgroundColor: '#ffffff', colorAdjust: 'exact', WebkitPrintColorAdjust: 'exact' }}>
            {theme.backgroundImage ? (
                <div className="absolute inset-0 z-0 overflow-hidden" style={{ opacity: bgOpacity }}>
                    <img src={theme.backgroundImage} style={{ width: '100%', height: '100%', objectFit: 'cover', objectPosition: `${bgX}% ${bgY}%`, transform: `scale(${bgScale})`, transformOrigin: `${bgX}% ${bgY}%` }} alt="" />
                </div>
            ) : (
                <><TopWave /><BottomWave /></>
            )}

            <div className="relative z-10 px-12 flex-grow flex flex-col" style={{ paddingTop: marginTop, paddingBottom: marginBottom }}>
                <div className="flex justify-between items-start mb-6">
                    <div className="mt-4">
                        <h1 className="text-4xl font-serif text-slate-900 mb-2 tracking-tight">
                            {isQuotation ? 'QUOTATION' : 'INVOICE'}
                        </h1>
                        <div className="text-xs text-slate-700 space-y-0.5">
                            <p><span className="font-bold text-slate-900">Document #:</span> {data.invoiceNumber}</p>
                            <p><span className="font-bold text-slate-900">Date:</span> {formatDate(data.date)}</p>
                        </div>
                    </div>
                    <div className="text-right"><Logo /></div>
                </div>

                <div className="flex gap-4 mb-8">
                    <div className="w-1/2">
                        <h3 className="font-bold text-[10px] uppercase mb-2 tracking-widest text-slate-900 border-b border-slate-200 pb-1">{isQuotation ? 'QUOTATION TO:' : 'BILL TO:'}</h3>
                        {client ? (
                            <div className="text-slate-800 font-medium">
                                <p className="text-sm font-bold mb-1">{client.name}</p>
                                <p className="whitespace-pre-line text-[10px] leading-normal">{client.address}</p>
                            </div>
                        ) : <p className="text-slate-300 text-[10px] italic">No client selected.</p>}
                    </div>
                    <div className="w-1/2 pl-4">
                        <h3 className="font-bold text-[10px] uppercase mb-2 tracking-widest text-slate-900 border-b border-slate-200 pb-1">FROM:</h3>
                         <div className="text-slate-800 font-medium">
                            <p className="text-sm font-bold mb-1">{sender.name}</p>
                            <p className="whitespace-pre-line text-[10px] leading-normal">{sender.address}</p>
                         </div>
                    </div>
                </div>

                <div className="relative mb-6"><Watermark /><ReferenceTable /></div>

                <div className="mt-auto mb-12">
                     <div className="flex gap-6 items-start">
                         <div className="w-[60%]">
                             <h3 className="font-serif font-bold uppercase mb-2 text-slate-900 text-[10px] tracking-widest">{isQuotation ? 'Terms & Conditions:' : 'Payment Info:'}</h3>
                             <div className="text-slate-700 font-medium space-y-0.5 text-[9px] leading-tight">
                                {isQuotation ? <p className="whitespace-pre-line">{data.notes || "1. 50% Advance"}</p> : 
                                  <>{sender.accountName && <p>Name: {sender.accountName}</p>}{sender.accountNumber && <p>Acc: {sender.accountNumber}</p>}</>
                                }
                             </div>
                         </div>
                         <div className="w-[40%]">
                             <div style={{ border: `2px solid ${tableColor}`, backgroundColor: '#ffffff' }}>
                                 <div className="flex justify-between p-2 text-slate-800 font-bold text-xs">
                                     <span>Sub Total:</span>
                                     <span>{currencyFormatter.format(subtotal)}</span>
                                 </div>
                                 <div className="p-2 text-white font-bold text-base flex justify-between items-center" style={{ backgroundColor: tableColor, borderTop: `2px solid ${tableColor}` }}>
                                     <span className="uppercase tracking-widest font-serif text-sm">TOTAL:</span>
                                     <span>{currencyFormatter.format(total)}</span>
                                 </div>
                             </div>
                         </div>
                     </div>
                </div>
                <div className="absolute bottom-6 left-0 right-0 text-center text-slate-500 text-[10px] font-bold">🌐 {sender.website}</div>
            </div>
        </div>
      );
  }

  return (
    <div className={containerClass} style={{ backgroundColor: '#ffffff' }}>
        <div className="p-12 flex flex-col h-full relative z-10">
            <div className="flex justify-between mb-8"><Logo /><div className="text-right"><h1 className="text-3xl font-bold" style={{ color: theme.colors.primary }}>{isQuotation ? 'QUOTATION' : 'INVOICE'}</h1></div></div>
            <ReferenceTable />
            <div className="flex justify-end mt-8">
                <div className="w-1/3 p-4 rounded-lg" style={{ backgroundColor: tableColor + '10' }}>
                    <div className="flex justify-between font-bold text-lg pt-2 border-t" style={{ color: tableColor }}><span>TOTAL</span><span>{currencyFormatter.format(total)}</span></div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default InvoicePreview;

import React, { useState, useEffect, useRef } from 'react';
import { 
  InvoiceData, 
  DEFAULT_SENDER, 
  LineItem,
  Client,
  MOCK_CLIENTS,
  SenderDetails,
  InvoiceTheme,
  InvoiceHistoryItem
} from '../types';
import ClientSelector from './ClientSelector';
import InvoicePreview from './InvoicePreview';
import SmartInput from './SmartInput';
import SettingsModal from './SettingsModal';
import HistoryModal from './HistoryModal';
import { Plus, Trash2, Download, Eye, Edit, ArrowLeft, FileText, Settings as SettingsIcon, Mail, LogOut, Loader2, Clock, Save as SaveIcon } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

interface InvoiceDashboardProps {
  onLogout: () => void;
}

const InvoiceDashboard: React.FC<InvoiceDashboardProps> = ({ onLogout }) => {
  const [clients, setClients] = useState<Client[]>(() => {
    try {
      const saved = localStorage.getItem('invoicify_clients');
      return saved ? JSON.parse(saved) : MOCK_CLIENTS;
    } catch (e) { return MOCK_CLIENTS; }
  });

  const [senderDetails, setSenderDetails] = useState<SenderDetails>(() => {
    try {
      const saved = localStorage.getItem('invoicify_sender');
      return saved ? JSON.parse(saved) : DEFAULT_SENDER;
    } catch { return DEFAULT_SENDER; }
  });

  const [customLogo, setCustomLogo] = useState<string | undefined>(() => localStorage.getItem('invoicify_logo') || undefined);
  const [customWatermark, setCustomWatermark] = useState<string | undefined>(() => localStorage.getItem('invoicify_custom_watermark') || undefined);
  const [invoicePrefix, setInvoicePrefix] = useState<string>(() => localStorage.getItem('invoicify_prefix') || 'AS');
  const [templateId, setTemplateId] = useState<string>(() => localStorage.getItem('invoicify_template') || 'classic-blue');
  const [customThemes, setCustomThemes] = useState<InvoiceTheme[]>(() => {
    try {
      const saved = localStorage.getItem('invoicify_custom_themes');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [showWatermark, setShowWatermark] = useState<boolean>(() => localStorage.getItem('invoicify_watermark') === 'true');
  const [watermarkOpacity, setWatermarkOpacity] = useState<number>(() => {
    const saved = localStorage.getItem('invoicify_watermark_opacity');
    return saved ? parseInt(saved, 10) : 10;
  });

  const [history, setHistory] = useState<InvoiceHistoryItem[]>(() => {
      try {
          const saved = localStorage.getItem('invoicify_history');
          return saved ? JSON.parse(saved) : [];
      } catch { return []; }
  });

  const [invoiceData, setInvoiceData] = useState<InvoiceData>({
    type: 'invoice',
    invoiceNumber: `${invoicePrefix}00125`,
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    sender: senderDetails,
    client: null,
    items: [{ id: '1', description: 'Consulting Services', quantity: 1, unitPrice: 0 }],
    notes: ''
  });

  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const exportRef = useRef<HTMLDivElement>(null);

  useEffect(() => { localStorage.setItem('invoicify_clients', JSON.stringify(clients)); }, [clients]);
  useEffect(() => {
    localStorage.setItem('invoicify_sender', JSON.stringify(senderDetails));
    setInvoiceData(prev => ({ ...prev, sender: senderDetails }));
  }, [senderDetails]);
  useEffect(() => { if (customLogo) localStorage.setItem('invoicify_logo', customLogo); else localStorage.removeItem('invoicify_logo'); }, [customLogo]);
  useEffect(() => { if (customWatermark) localStorage.setItem('invoicify_custom_watermark', customWatermark); else localStorage.removeItem('invoicify_custom_watermark'); }, [customWatermark]);
  useEffect(() => { localStorage.setItem('invoicify_prefix', invoicePrefix); }, [invoicePrefix]);
  useEffect(() => { localStorage.setItem('invoicify_template', templateId); }, [templateId]);
  useEffect(() => { localStorage.setItem('invoicify_custom_themes', JSON.stringify(customThemes)); }, [customThemes]);
  useEffect(() => { localStorage.setItem('invoicify_watermark', String(showWatermark)); }, [showWatermark]);
  useEffect(() => { localStorage.setItem('invoicify_watermark_opacity', String(watermarkOpacity)); }, [watermarkOpacity]);
  useEffect(() => { localStorage.setItem('invoicify_history', JSON.stringify(history)); }, [history]);

  const saveToHistory = (dataToSave: InvoiceData) => {
      setHistory(prev => {
          const index = prev.findIndex(item => item.data.invoiceNumber === dataToSave.invoiceNumber);
          if (index >= 0) {
              const updatedHistory = [...prev];
              updatedHistory[index] = { ...updatedHistory[index], lastModified: Date.now(), data: dataToSave };
              return updatedHistory;
          } else {
              return [{ id: uuidv4(), createdAt: Date.now(), lastModified: Date.now(), data: dataToSave }, ...prev];
          }
      });
  };

  const handleExport = async () => {
    saveToHistory(invoiceData);
    setIsExporting(true);

    // Increased timeout to ensure all images and fonts in the invisible root are loaded
    await new Promise(resolve => setTimeout(resolve, 1500));

    const element = exportRef.current;
    if (!element) {
        setIsExporting(false);
        return;
    }

    const html2pdf = (window as any).html2pdf;
    if (!html2pdf) {
        alert("PDF generator not found. Printing instead.");
        window.print();
        setIsExporting(false);
        return;
    }

    const opt = {
        margin: 0,
        filename: `${invoiceData.invoiceNumber || 'invoice'}.pdf`,
        image: { type: 'jpeg', quality: 1.0 },
        html2canvas: { 
            scale: 3, // High scale for crisp text
            useCORS: true, 
            logging: false,
            letterRendering: true,
            // Force capture at A4 dimensions in pixels (approx 794px wide)
            width: 794,
            height: 1123,
            backgroundColor: '#ffffff'
        },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait', compress: true }
    };

    try {
        await html2pdf().set(opt).from(element).save();
    } catch (err) {
        console.error("PDF export failed:", err);
        alert("PDF generation failed. Using browser print instead.");
        window.print();
    } finally {
        setIsExporting(false);
    }
  };

  const addItem = () => {
    setInvoiceData(prev => ({ ...prev, items: [...prev.items, { id: uuidv4(), description: '', quantity: 1, unitPrice: 0 }] }));
  };

  const updateItem = (id: string, field: keyof LineItem, value: any) => {
    setInvoiceData(prev => ({ ...prev, items: prev.items.map(i => i.id === id ? { ...i, [field]: value } : i) }));
  };

  const removeItem = (id: string) => {
    setInvoiceData(prev => ({ ...prev, items: prev.items.filter(i => i.id !== id) }));
  };

  return (
    <>
      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} 
        senderDetails={senderDetails} onUpdateSender={setSenderDetails} 
        logo={customLogo} onUpdateLogo={setCustomLogo} 
        invoicePrefix={invoicePrefix} onUpdatePrefix={setInvoicePrefix} 
        clients={clients} onDeleteClient={(id) => setClients(c => c.filter(x => x.id !== id))} 
        templateId={templateId} onUpdateTemplate={setTemplateId} 
        showWatermark={showWatermark} onToggleWatermark={setShowWatermark} 
        customThemes={customThemes} onAddTheme={(t) => setCustomThemes(prev => [...prev, t])} 
        onDeleteTheme={(id) => setCustomThemes(prev => prev.filter(t => t.id !== id))} 
        onUpdateCustomThemeDetails={(ut) => setCustomThemes(prev => prev.map(t => t.id === ut.id ? ut : t))}
        customWatermark={customWatermark} onUpdateCustomWatermark={setCustomWatermark} 
        watermarkOpacity={watermarkOpacity} onUpdateWatermarkOpacity={setWatermarkOpacity} 
      />

      <HistoryModal isOpen={isHistoryOpen} onClose={() => setIsHistoryOpen(false)} history={history} onLoad={setInvoiceData} onDelete={(id) => setHistory(h => h.filter(x => x.id !== id))} />

      <div className="min-h-screen flex flex-col md:flex-row font-sans print:hidden">
        <div className={`w-full md:w-5/12 lg:w-4/12 bg-white border-r border-slate-200 h-[calc(100vh-60px)] md:h-screen overflow-y-auto ${activeTab === 'preview' ? 'hidden md:block' : ''}`}>
          <div className="p-6">
            <div className="flex justify-between items-center mb-8">
              <h1 className="text-2xl font-bold text-slate-900">Invoicify</h1>
              <div className="flex gap-2">
                <button onClick={() => setIsHistoryOpen(true)} className="p-2 text-slate-400 hover:text-blue-600"><Clock size={20} /></button>
                <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-400 hover:text-slate-600"><SettingsIcon size={20} /></button>
                <button onClick={onLogout} className="p-2 text-slate-400 hover:text-red-600"><LogOut size={20} /></button>
              </div>
            </div>

            <section className="mb-8">
              <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Bill To</h2>
              <ClientSelector selectedClient={invoiceData.client} onSelectClient={(client) => setInvoiceData(prev => ({ ...prev, client }))} clients={clients} onAddClient={(c) => setClients(prev => [...prev, c])} onUpdateClient={(c) => setClients(prev => prev.map(x => x.id === c.id ? c : x))} />
            </section>

            <section className="mb-8">
              <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4">Items</h2>
              <SmartInput onItemsParsed={(items) => setInvoiceData(prev => ({ ...prev, items: [...prev.items, ...items] }))} />
              <div className="space-y-4">
                {invoiceData.items.map((item, index) => (
                  <div key={item.id} className="bg-slate-50 p-4 rounded-lg border relative group">
                    <button onClick={() => removeItem(item.id)} className="absolute right-2 top-2 text-slate-400 hover:text-red-500"><Trash2 size={16} /></button>
                    <input type="text" value={item.description} onChange={(e) => updateItem(item.id, 'description', e.target.value)} className="w-full bg-white border p-2 rounded text-sm mb-3" placeholder="Description" />
                    <div className="flex gap-3">
                      <input type="number" value={item.quantity} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} className="w-1/4 bg-white border p-2 rounded text-sm" />
                      <input type="number" value={item.unitPrice} onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))} className="w-3/4 bg-white border p-2 rounded text-sm" />
                    </div>
                  </div>
                ))}
              </div>
              <button onClick={addItem} className="mt-4 w-full py-2 border border-dashed border-slate-300 rounded-lg text-slate-500 hover:bg-slate-50 flex items-center justify-center gap-2 text-sm"><Plus size={16} /> Add Item</button>
            </section>
          </div>
        </div>

        <div className={`w-full md:w-7/12 lg:w-8/12 bg-slate-100 h-[calc(100vh-60px)] md:h-screen overflow-y-auto relative ${activeTab === 'edit' ? 'hidden md:block' : ''}`}>
          <div className="sticky top-0 z-10 p-4 flex justify-end gap-3 pointer-events-none">
             <div className="pointer-events-auto flex gap-3">
                <button onClick={() => saveToHistory(invoiceData)} className="bg-white p-2.5 rounded-full shadow-lg border hover:bg-slate-50 transition-all"><SaveIcon size={18} /></button>
                <button onClick={handleExport} disabled={isExporting} className="bg-slate-900 text-white px-5 py-2.5 rounded-full shadow-lg flex items-center gap-2 font-medium disabled:bg-slate-600">
                  {isExporting ? <Loader2 size={18} className="animate-spin" /> : <Download size={18} />}
                  <span>{isExporting ? 'Generating...' : 'Download PDF'}</span>
                </button>
             </div>
          </div>
          <div className="p-4 md:p-12 flex justify-center items-start min-h-full">
             <div className="transform scale-[0.45] sm:scale-[0.7] lg:scale-100 origin-top shadow-2xl bg-white">
                <InvoicePreview data={invoiceData} logoSrc={customLogo} templateId={templateId} showWatermark={showWatermark} customThemes={customThemes} customWatermark={customWatermark} watermarkOpacity={watermarkOpacity} />
             </div>
          </div>
        </div>
      </div>

      {/* FIXED EXPORT ROOT: Use visibility hidden instead of negative positioning for better rendering stability */}
      <div style={{ position: 'fixed', top: 0, left: 0, width: '210mm', pointerEvents: 'none', zIndex: -100, visibility: 'hidden' }}>
        <div ref={exportRef} style={{ width: '210mm', height: '297mm', backgroundColor: '#ffffff' }}>
            <InvoicePreview data={invoiceData} logoSrc={customLogo} templateId={templateId} showWatermark={showWatermark} customThemes={customThemes} customWatermark={customWatermark} watermarkOpacity={watermarkOpacity} />
        </div>
      </div>
    </>
  );
};

